import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum EmotionType {
  HAPPY = 'Happy',
  SAD = 'Sad',
  ANGRY = 'Angry',
  SURPRISED = 'Surprised',
  NEUTRAL = 'Neutral',
  CONFUSED = 'Confused',
  FRUSTRATED = 'Frustrated',
  ANXIOUS = 'Anxious'
}

export enum EngagementLevel {
  HIGH = 'High',
  MEDIUM = 'Medium',
  LOW = 'Low'
}

export interface EmotionalAnalysis {
  emotion: EmotionType;
  engagement: EngagementLevel;
  stressScore: number; // 0-10
  confidence: number;
  summary: string;
}

export interface StudentRecord {
  id: string;
  name: string;
  avatar: string;
  lastAnalysis?: EmotionalAnalysis;
  history: EmotionalAnalysis[];
  isFlagged: boolean;
}

export interface TextSentimentResult {
  sentiment: string;
  stressScore: number;
  keywords: string[];
  interventionRecommended: boolean;
  analysis: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { EmotionalAnalysis, TextSentimentResult } from "../types";

const API_KEY = process.env.API_KEY || '';

export const analyzeFaceExpression = async (base64Image: string): Promise<EmotionalAnalysis | null> => {
  if (!API_KEY) return null;
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image,
            },
          },
          {
            text: "Analyze this student's facial expression for an emotional analytics platform. Determine their primary emotion, engagement level with schoolwork, stress score (0-10), and a brief summary.",
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            emotion: { type: Type.STRING, description: "One of: Happy, Sad, Angry, Surprised, Neutral, Confused, Frustrated, Anxious" },
            engagement: { type: Type.STRING, description: "One of: High, Medium, Low" },
            stressScore: { type: Type.NUMBER, description: "Scale from 0 (relaxed) to 10 (highly stressed)" },
            confidence: { type: Type.NUMBER, description: "Confidence score 0 to 1" },
            summary: { type: Type.STRING, description: "A one-sentence summary of the visual cues observed." },
          },
          required: ["emotion", "engagement", "stressScore", "confidence", "summary"],
        },
      },
    });

    const result = JSON.parse(response.text || '{}');
    return result as EmotionalAnalysis;
  } catch (error) {
    console.error("Gemini Image Analysis Error:", error);
    return null;
  }
};

export const analyzeStudentJournal = async (text: string): Promise<TextSentimentResult | null> => {
  if (!API_KEY) return null;
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze the following student reflection or journal entry for emotional health and engagement markers: "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sentiment: { type: Type.STRING },
            stressScore: { type: Type.NUMBER },
            keywords: { 
                type: Type.ARRAY,
                items: { type: Type.STRING }
            },
            interventionRecommended: { type: Type.BOOLEAN },
            analysis: { type: Type.STRING, description: "Contextual reasoning for the analysis." },
          },
          required: ["sentiment", "stressScore", "keywords", "interventionRecommended", "analysis"],
        },
      },
    });

    const result = JSON.parse(response.text || '{}');
    return result as TextSentimentResult;
  } catch (error) {
    console.error("Gemini Text Analysis Error:", error);
    return null;
  }
};

