import React, { useRef, useState, useEffect } from 'react';
import { analyzeFaceExpression } from '../services/geminiService';
import { EmotionalAnalysis, StudentRecord } from '../types';

interface CaptureUIProps {
  students: StudentRecord[];
  onResult: (studentId: string, analysis: EmotionalAnalysis) => void;
}

const CaptureUI: React.FC<CaptureUIProps> = ({ students, onResult }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCapturing, setIsCapturing] = useState(false);
  const [selectedStudent, setSelectedStudent] = useState(students[0]?.id || '');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [lastAnalysis, setLastAnalysis] = useState<EmotionalAnalysis | null>(null);

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCapturing(true);
      }
    } catch (err) {
      console.error("Camera error:", err);
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
    }
    setIsCapturing(false);
  };

  const captureFrame = async () => {
    if (!videoRef.current || !canvasRef.current || !selectedStudent) return;

    setIsAnalyzing(true);
    const context = canvasRef.current.getContext('2d');
    if (context) {
      context.drawImage(videoRef.current, 0, 0, 640, 480);
      const dataUrl = canvasRef.current.toDataURL('image/jpeg');
      const base64Data = dataUrl.split(',')[1];

      const result = await analyzeFaceExpression(base64Data);
      if (result) {
        setLastAnalysis(result);
        onResult(selectedStudent, result);
      }
    }
    setIsAnalyzing(false);
  };

  return (
    <div className="bg-white rounded-2xl border border-slate-100 p-8 shadow-sm">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
        <div className="space-y-6">
          <div className="relative rounded-2xl overflow-hidden bg-slate-900 aspect-video flex items-center justify-center border-4 border-slate-800">
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className="w-full h-full object-cover"
            />
            <canvas ref={canvasRef} width="640" height="480" className="hidden" />

            {isAnalyzing && (
              <div className="absolute inset-0 bg-indigo-900/40 backdrop-blur-sm flex flex-col items-center justify-center text-white">
                <div className="w-12 h-12 border-4 border-white/20 border-t-white rounded-full animate-spin mb-4"></div>
                <p className="font-semibold tracking-wide">AI Processing Facial Cues...</p>
              </div>
            )}

            {!isCapturing && !isAnalyzing && (
              <button 
                onClick={startCamera}
                className="bg-white text-slate-900 px-6 py-2 rounded-full font-bold shadow-lg"
              >
                Start Camera
              </button>
            )}
          </div>

          <div className="flex flex-col gap-4">
            <label className="text-sm font-semibold text-slate-600">Assign Analysis To Student:</label>
            <select 
              value={selectedStudent}
              onChange={(e) => setSelectedStudent(e.target.value)}
              className="w-full p-4 rounded-xl border border-slate-200 bg-slate-50 focus:ring-2 focus:ring-indigo-500 outline-none"
            >
              {students.map(s => (
                <option key={s.id} value={s.id}>{s.name}</option>
              ))}
            </select>
            <button
              onClick={captureFrame}
              disabled={isAnalyzing || !isCapturing}
              className={`w-full py-4 rounded-xl font-bold text-white transition-all transform active:scale-95 ${
                isAnalyzing || !isCapturing ? 'bg-slate-300' : 'bg-indigo-600 hover:bg-indigo-700 shadow-xl'
              }`}
            >
              Analyze Live Expression
            </button>
          </div>
        </div>

        <div className="flex flex-col justify-center">
          {lastAnalysis ? (
            <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-500">
              <h3 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
                Analysis Results 
                <span className="text-indigo-600 px-2 py-0.5 bg-indigo-50 rounded-lg text-sm">
                  {Math.round(lastAnalysis.confidence * 100)}% Conf.
                </span>
              </h3>

              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                  <p className="text-xs text-slate-400 font-bold uppercase mb-1">Emotion</p>
                  <p className="text-xl font-bold text-slate-800">{lastAnalysis.emotion}</p>
                </div>
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                  <p className="text-xs text-slate-400 font-bold uppercase mb-1">Engagement</p>
                  <p className={`text-xl font-bold ${
                    lastAnalysis.engagement === 'High' ? 'text-emerald-600' : 
                    lastAnalysis.engagement === 'Low' ? 'text-rose-600' : 'text-amber-600'
                  }`}>
                    {lastAnalysis.engagement}
                  </p>
                </div>
              </div>

              <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100">
                <div className="flex justify-between items-center mb-4">
                  <p className="text-sm font-bold text-slate-500 uppercase">Stress Score</p>
                  <p className="text-2xl font-black text-indigo-600">{lastAnalysis.stressScore}<span className="text-sm font-medium text-slate-400">/10</span></p>
                </div>
                <div className="w-full h-3 bg-slate-200 rounded-full overflow-hidden">
                  <div 
                    className={`h-full transition-all duration-1000 ${
                      lastAnalysis.stressScore > 7 ? 'bg-rose-500' : 
                      lastAnalysis.stressScore > 4 ? 'bg-amber-500' : 'bg-emerald-500'
                    }`}
                    style={{ width: `${lastAnalysis.stressScore * 10}%` }}
                  />
                </div>
              </div>

              <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100">
                <p className="text-indigo-900 font-medium leading-relaxed italic">
                  "{lastAnalysis.summary}"
                </p>
              </div>

              <div className="flex items-center gap-2 text-sm text-slate-400 italic">
                <span>ℹ️</span> Data processed locally for student privacy protection.
              </div>
            </div>
          ) : (
            <div className="text-center space-y-4 py-20 bg-slate-50 rounded-3xl border-2 border-dashed border-slate-200">
              <div className="text-6xl grayscale opacity-30">🔍</div>
              <p className="text-slate-400 max-w-xs mx-auto">Select a student and capture their expression to begin real-time analysis.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default CaptureUI;

import React, { useState } from 'react';
import { analyzeStudentJournal } from '../services/geminiService';
import { TextSentimentResult, StudentRecord } from '../types';

interface JournalUIProps {
  students: StudentRecord[];
}

const JournalUI: React.FC<JournalUIProps> = ({ students }) => {
  const [journalText, setJournalText] = useState('');
  const [selectedStudent, setSelectedStudent] = useState(students[0]?.id || '');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<TextSentimentResult | null>(null);

  const handleAnalyze = async () => {
    if (!journalText.trim()) return;
    setIsAnalyzing(true);
    const analysis = await analyzeStudentJournal(journalText);
    if (analysis) {
      setResult(analysis);
    }
    setIsAnalyzing(false);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
        <h2 className="text-2xl font-bold text-slate-800 mb-6 flex items-center gap-3">
          <span>✍️</span> Sentiment Analysis Engine
        </h2>

        <div className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-500">Student Source:</label>
              <select 
                value={selectedStudent}
                onChange={(e) => setSelectedStudent(e.target.value)}
                className="w-full p-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500"
              >
                {students.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-500">Paste Reflection / Essay Segment:</label>
            <textarea
              value={journalText}
              onChange={(e) => setJournalText(e.target.value)}
              placeholder="e.g. I felt really overwhelmed today with the math project. It felt like I couldn't understand any of the concepts..."
              className="w-full h-48 p-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
            />
          </div>

          <button
            onClick={handleAnalyze}
            disabled={isAnalyzing || !journalText.trim()}
            className="w-full py-4 rounded-xl bg-indigo-600 hover:bg-indigo-700 text-white font-bold transition-all disabled:opacity-50 flex items-center justify-center gap-2"
          >
            {isAnalyzing ? (
              <><div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin" /> Analyzing Sentiment...</>
            ) : (
              'Process Text Data'
            )}
          </button>
        </div>
      </div>

      {result && (
        <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
          <div className="flex items-start justify-between">
            <div>
              <h3 className="text-xl font-bold text-slate-800">Insights for Student Submission</h3>
              <p className="text-slate-500">Primary Sentiment: <span className="text-indigo-600 font-semibold">{result.sentiment}</span></p>
            </div>
            {result.interventionRecommended && (
              <div className="bg-rose-100 text-rose-700 px-4 py-2 rounded-xl text-sm font-bold border border-rose-200 animate-pulse">
                Intervention Suggested
              </div>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="p-4 bg-slate-50 rounded-2xl">
              <p className="text-xs font-bold text-slate-400 uppercase mb-2">Stress Level</p>
              <p className="text-2xl font-black text-slate-800">{result.stressScore}/10</p>
            </div>
            <div className="md:col-span-2 p-4 bg-slate-50 rounded-2xl">
              <p className="text-xs font-bold text-slate-400 uppercase mb-2">Emotional Keywords</p>
              <div className="flex flex-wrap gap-2">
                {result.keywords.map(kw => (
                  <span key={kw} className="px-3 py-1 bg-white border border-slate-200 rounded-lg text-xs font-semibold text-slate-700">
                    {kw}
                  </span>
                ))}
              </div>
            </div>
          </div>

          <div className="bg-indigo-50 p-6 rounded-2xl border border-indigo-100">
            <h4 className="font-bold text-indigo-900 mb-2">AI Summary & Reasoning:</h4>
            <p className="text-indigo-800 leading-relaxed">{result.analysis}</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default JournalUI;

