import React, { useState } from 'react';
import { StudentRecord } from '../types';

interface StudentRosterProps {
  students: StudentRecord[];
  onAddStudent: (name: string) => void;
}

const StudentRoster: React.FC<StudentRosterProps> = ({ students, onAddStudent }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newStudentName, setNewStudentName] = useState('');
  const [searchQuery, setSearchQuery] = useState('');

  const filteredStudents = students.filter(s => 
    s.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newStudentName.trim()) {
      onAddStudent(newStudentName.trim());
      setNewStudentName('');
      setIsModalOpen(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Class Roster</h2>
          <p className="text-slate-500 text-sm">{students.length} Students Enrolled</p>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <div className="relative flex-1 md:flex-none">
            <input 
              type="text" 
              placeholder="Search students..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full md:w-64 pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 bg-white transition-all shadow-sm"
            />
            <span className="absolute left-3 top-3 opacity-30 text-lg">🔍</span>
          </div>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg active:scale-95"
          >
            <span className="text-xl">+</span>
            <span>Add Student</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {filteredStudents.map((student) => (
          <div 
            key={student.id} 
            className={`bg-white p-6 rounded-3xl border transition-all hover:shadow-xl hover:-translate-y-1 group ${
              student.isFlagged ? 'border-rose-200 shadow-rose-50 shadow-sm' : 'border-slate-100 shadow-sm'
            }`}
          >
            <div className="flex items-center gap-4 mb-6">
              <div className="relative">
                <img src={student.avatar} className="w-16 h-16 rounded-2xl bg-slate-100 object-cover shadow-inner" />
                {student.isFlagged && (
                  <div className="absolute -top-1 -right-1 w-4 h-4 bg-rose-500 rounded-full border-2 border-white animate-pulse"></div>
                )}
              </div>
              <div>
                <h3 className="font-bold text-slate-800 text-lg group-hover:text-indigo-600 transition-colors">{student.name}</h3>
                <p className="text-xs text-slate-500 font-mono tracking-tighter">ID: {student.id.toUpperCase()}</p>
              </div>
            </div>

            <div className="space-y-3 bg-slate-50/50 p-4 rounded-2xl border border-slate-100">
              <div className="flex justify-between text-xs">
                <span className="text-slate-500 uppercase font-bold tracking-wider">Current Emotion</span>
                <span className="font-bold text-slate-800">{student.lastAnalysis?.emotion || 'Unknown'}</span>
              </div>
              <div className="flex justify-between text-xs">
                <span className="text-slate-500 uppercase font-bold tracking-wider">Engagement</span>
                <span className={`font-bold ${
                  student.lastAnalysis?.engagement === 'High' ? 'text-emerald-600' : 
                  student.lastAnalysis?.engagement === 'Low' ? 'text-rose-600' : 'text-amber-600'
                }`}>
                  {student.lastAnalysis?.engagement || 'Unmeasured'}
                </span>
              </div>
              <div className="flex justify-between text-xs">
                <span className="text-slate-500 uppercase font-bold tracking-wider">Stress Score</span>
                <span className="font-bold text-slate-800">{student.lastAnalysis?.stressScore || 0}/10</span>
              </div>
            </div>

            <div className="mt-6 pt-6 border-t border-slate-100 flex gap-2">
              <button className="flex-1 py-2.5 rounded-xl bg-slate-100 text-slate-600 font-bold text-xs hover:bg-slate-200 transition-colors">
                View History
              </button>
              <button className="flex-1 py-2.5 rounded-xl bg-indigo-50 text-indigo-600 font-bold text-xs hover:bg-indigo-100 transition-colors">
                Quick Action
              </button>
            </div>
          </div>
        ))}
        {filteredStudents.length === 0 && (
          <div className="col-span-full py-20 text-center bg-white rounded-3xl border border-dashed border-slate-200">
            <p className="text-slate-400 font-medium">No students found matching your search.</p>
          </div>
        )}
      </div>

      {/* Add Student Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div 
            className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-300"
            onClick={() => setIsModalOpen(false)}
          />
          <div className="relative bg-white w-full max-w-md rounded-3xl shadow-2xl p-8 animate-in zoom-in-95 fade-in duration-300">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-800">Add New Student</h3>
              <button 
                onClick={() => setIsModalOpen(false)}
                className="text-slate-400 hover:text-slate-600 text-2xl"
              >
                &times;
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-500 uppercase tracking-wider">Full Name</label>
                <input 
                  type="text" 
                  autoFocus
                  required
                  value={newStudentName}
                  onChange={(e) => setNewStudentName(e.target.value)}
                  placeholder="e.g. John Doe"
                  className="w-full p-4 rounded-2xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 bg-slate-50 transition-all"
                />
              </div>

              <div className="p-4 bg-indigo-50 rounded-2xl border border-indigo-100 flex gap-3 items-start">
                <span className="text-xl">✨</span>
                <p className="text-sm text-indigo-800 leading-relaxed">
                  A unique student ID and profile avatar will be automatically generated upon creation.
                </p>
              </div>

              <div className="flex gap-3 pt-2">
                <button 
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 py-4 rounded-2xl font-bold text-slate-500 hover:bg-slate-100 transition-all"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-4 rounded-2xl bg-indigo-600 text-white font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-all"
                >
                  Create Student
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default StudentRoster;

