import React, { useState, useRef } from 'react';
import { StudentRecord } from '../types';

interface StudentRosterProps {
  students: StudentRecord[];
  onAddStudent: (name: string, customAvatar?: string) => void;
  onUpdateStudent: (id: string, updates: Partial<StudentRecord>) => void;
}

const getAvatarUrl = (seed: string) => `https://api.dicebear.com/7.x/avataaars/svg?seed=${encodeURIComponent(seed)}`;

const StudentRoster: React.FC<StudentRosterProps> = ({ students, onAddStudent, onUpdateStudent }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newStudentName, setNewStudentName] = useState('');
  const [newStudentAvatar, setNewStudentAvatar] = useState<string>(getAvatarUrl(Math.random().toString()));
  const [searchQuery, setSearchQuery] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const editAvatarRef = useRef<HTMLInputElement>(null);
  const [editingStudentId, setEditingStudentId] = useState<string | null>(null);

  const filteredStudents = students.filter(s => 
    s.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, forNewStudent: boolean) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (forNewStudent) {
          setNewStudentAvatar(base64String);
        } else if (editingStudentId) {
          onUpdateStudent(editingStudentId, { avatar: base64String });
          setEditingStudentId(null);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const shuffleAvatar = () => {
    setNewStudentAvatar(getAvatarUrl(Math.random().toString()));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newStudentName.trim()) {
      onAddStudent(newStudentName.trim(), newStudentAvatar);
      setNewStudentName('');
      setNewStudentAvatar(getAvatarUrl(Math.random().toString()));
      setIsModalOpen(false);
    }
  };

  const triggerEditAvatar = (id: string) => {
    setEditingStudentId(id);
    editAvatarRef.current?.click();
  };

  return (
    <div className="space-y-6">
      <input 
        type="file" 
        ref={editAvatarRef} 
        className="hidden" 
        accept="image/*" 
        onChange={(e) => handleFileUpload(e, false)} 
      />

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 dark:text-slate-100">Class Roster</h2>
          <p className="text-slate-500 dark:text-slate-400 text-sm">{students.length} Students Enrolled</p>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <div className="relative flex-1 md:flex-none">
            <input 
              type="text" 
              placeholder="Search students..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full md:w-64 pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-800 outline-none focus:ring-2 focus:ring-indigo-500 bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-200 transition-all shadow-sm"
            />
            <span className="absolute left-3 top-3 opacity-30 text-lg">🔍</span>
          </div>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg active:scale-95"
          >
            <span className="text-xl">+</span>
            <span>Add Student</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {filteredStudents.map((student) => (
          <div 
            key={student.id} 
            className={`bg-white dark:bg-slate-900 p-6 rounded-3xl border transition-all hover:shadow-xl hover:-translate-y-1 group ${
              student.isFlagged ? 'border-rose-200 dark:border-rose-900/50 shadow-rose-50 dark:shadow-none shadow-sm' : 'border-slate-100 dark:border-slate-800 shadow-sm'
            }`}
          >
            <div className="flex items-center gap-4 mb-6">
              <div className="relative group/avatar">
                <img src={student.avatar} className="w-16 h-16 rounded-2xl bg-slate-100 dark:bg-slate-800 object-cover shadow-inner" />
                <button 
                  onClick={() => triggerEditAvatar(student.id)}
                  className="absolute inset-0 bg-black/40 rounded-2xl flex items-center justify-center opacity-0 group-hover/avatar:opacity-100 transition-opacity"
                >
                  <span className="text-white text-lg">📷</span>
                </button>
                {student.isFlagged && (
                  <div className="absolute -top-1 -right-1 w-4 h-4 bg-rose-500 rounded-full border-2 border-white dark:border-slate-900 animate-pulse"></div>
                )}
              </div>
              <div>
                <h3 className="font-bold text-slate-800 dark:text-slate-100 text-lg group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{student.name}</h3>
                <p className="text-xs text-slate-500 dark:text-slate-400 font-mono tracking-tighter">ID: {student.id.toUpperCase()}</p>
              </div>
            </div>

            <div className="space-y-3 bg-slate-50 dark:bg-slate-950 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
              <div className="flex justify-between text-xs">
                <span className="text-slate-500 dark:text-slate-400 uppercase font-bold tracking-wider">Current Emotion</span>
                <span className="font-bold text-slate-800 dark:text-slate-100">{student.lastAnalysis?.emotion || 'Unknown'}</span>
              </div>
              <div className="flex justify-between text-xs">
                <span className="text-slate-500 dark:text-slate-400 uppercase font-bold tracking-wider">Engagement</span>
                <span className={`font-bold ${
                  student.lastAnalysis?.engagement === 'High' ? 'text-emerald-600 dark:text-emerald-400' : 
                  student.lastAnalysis?.engagement === 'Low' ? 'text-rose-600 dark:text-rose-400' : 'text-amber-600'
                }`}>
                  {student.lastAnalysis?.engagement || 'Unmeasured'}
                </span>
              </div>
              <div className="flex justify-between text-xs">
                <span className="text-slate-500 dark:text-slate-400 uppercase font-bold tracking-wider">Stress Score</span>
