                &times;
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="flex flex-col items-center gap-4">
                <div className="relative group/new-avatar">
                  <div className={`w-24 h-24 rounded-3xl bg-slate-100 dark:bg-slate-800 overflow-hidden shadow-lg border-2 ${isGeneratingAI ? 'border-indigo-400 animate-pulse' : 'border-indigo-100 dark:border-indigo-900'}`}>
