import React, { useState, useMemo } from 'react';
import { 
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell, AreaChart, Area 
} from 'recharts';
import { StudentRecord, EmotionType } from '../types';

interface DashboardProps {
  students: StudentRecord[];
  isStudentView?: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ students, isStudentView }) => {
  const [viewMode, setViewMode] = useState<'class' | 'individual'>(isStudentView ? 'individual' : 'class');
  const [selectedStudentId, setSelectedStudentId] = useState<string>(students[0]?.id || '');

  const COLORS = ['#10b981', '#6366f1', '#f59e0b', '#ef4444'];

  const selectedStudent = useMemo(() => 
    students.find(s => s.id === selectedStudentId) || students[0],
    [students, selectedStudentId]
  );

  // Class Aggregates
  const emotionData = useMemo(() => [
    { name: 'Happy', count: students.filter(s => s.lastAnalysis?.emotion === EmotionType.HAPPY).length },
    { name: 'Neutral', count: students.filter(s => s.lastAnalysis?.emotion === EmotionType.NEUTRAL).length },
    { name: 'Focused', count: students.filter(s => s.lastAnalysis?.engagement === 'High').length },
    { name: 'Concern', count: students.filter(s => s.isFlagged).length },
  ], [students]);

  const trendData = useMemo(() => {
    if (viewMode === 'individual' && selectedStudent?.history.length > 0) {
      return selectedStudent.history.map((h, i) => ({ time: `Day ${i + 1}`, value: h.stressScore }));
    }
    // Mock class trend
    return [
      { time: 'Mon', value: 3 }, { time: 'Tue', value: 4 }, { time: 'Wed', value: 2 },
      { time: 'Thu', value: 6 }, { time: 'Fri', value: 4 }
    ];
  }, [viewMode, selectedStudent]);

  const flaggedStudents = students.filter(s => s.isFlagged);

  return (
    <div className="space-y-6">
      {/* Header & Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-slate-100 tracking-tight">
            {isStudentView ? `Hey, ${selectedStudent?.name}!` : 'Class Insight Engine'}
          </h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium">
            {isStudentView ? 'Keep track of your learning mindset and wellness.' : 'Real-time emotional monitoring for your active session.'}
          </p>
        </div>

        {!isStudentView && (
          <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-2xl border border-slate-200 dark:border-slate-700">
            <button 
              onClick={() => setViewMode('class')}
              className={`px-4 py-2 rounded-xl text-sm font-bold transition-all ${
                viewMode === 'class' ? 'bg-white dark:bg-slate-700 text-indigo-600 shadow-sm' : 'text-slate-500'
              }`}
            >
              📊 Class Summary
            </button>
            <button 
              onClick={() => setViewMode('individual')}
              className={`px-4 py-2 rounded-xl text-sm font-bold transition-all ${
                viewMode === 'individual' ? 'bg-white dark:bg-slate-700 text-indigo-600 shadow-sm' : 'text-slate-500'
              }`}
            >
              👤 Student Drill-down
            </button>
          </div>
        )}
      </div>

      {/* Individual Drilldown Selector (Teachers Only) */}
      {!isStudentView && viewMode === 'individual' && (
        <div className="flex items-center gap-4 bg-white dark:bg-slate-900 p-4 rounded-2xl border border-indigo-100 dark:border-indigo-900/30 animate-in fade-in zoom-in-95 duration-300">
          <span className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Select Student:</span>
          <select 
            value={selectedStudentId}
            onChange={(e) => setSelectedStudentId(e.target.value)}
            className="flex-1 max-w-xs p-3 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 text-slate-800 dark:text-slate-100 outline-none focus:ring-2 focus:ring-indigo-500"
          >
            {students.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
          </select>
        </div>
      )}

      {/* Main Stats Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Trend Graph */}
        <div className="lg:col-span-2 bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800">
          <h3 className="text-lg font-bold mb-6 flex items-center gap-2 dark:text-slate-100 uppercase tracking-wider text-slate-400">
            {viewMode === 'individual' ? 'Stress Intensity Trend' : 'Class Engagement Timeline'}
