                    <stop offset="5%" stopColor={isStudentView ? "#10b981" : "#6366f1"} stopOpacity={0.3}/>
                    <stop offset="95%" stopColor={isStudentView ? "#10b981" : "#6366f1"} stopOpacity={0}/>
