      {viewMode === 'class' && (
        <div className="bg-rose-50 dark:bg-rose-900/10 border border-rose-100 dark:border-rose-900/30 rounded-3xl p-8">
          <h3 className="text-rose-800 dark:text-rose-400 font-black uppercase tracking-widest text-sm mb-6 flex items-center gap-2">
            <span>🚨</span> Attention Required List
          </h3>
