                    <p className="font-bold text-slate-800 dark:text-slate-100">{student.name}</p>
                    <p className="text-xs text-rose-600 dark:text-rose-400 font-bold uppercase">Stress Spike: {student.lastAnalysis?.stressScore}/10</p>
                  </div>
                </div>
                <button 
                  onClick={() => {
                    setSelectedStudentId(student.id);
                    setViewMode('individual');
                  }}
                  className="bg-rose-600 text-white px-4 py-2 rounded-xl text-xs font-bold hover:bg-rose-700 transition-colors shadow-lg shadow-rose-200 dark:shadow-none"
                >
                  View Details
                </button>
              </div>
            ))}
            {flaggedStudents.length === 0 && (
              <p className="text-emerald-600 dark:text-emerald-400 text-sm font-bold flex items-center gap-2">
                <span>✅</span> All students are within normal emotional thresholds.
              </p>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

