import React, { useRef, useState, useEffect } from 'react';
import { analyzeFaceExpression } from '../services/geminiService';
import { EmotionalAnalysis, StudentRecord } from '../types';

interface CaptureUIProps {
  students: StudentRecord[];
  onResult: (studentId: string, analysis: EmotionalAnalysis) => void;
  isStudentView?: boolean;
}

const CaptureUI: React.FC<CaptureUIProps> = ({ students, onResult, isStudentView }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCapturing, setIsCapturing] = useState(false);
  const [selectedStudent, setSelectedStudent] = useState(students[0]?.id || '');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [lastAnalysis, setLastAnalysis] = useState<EmotionalAnalysis | null>(null);

  // Sync selection if students list changes (e.g. after first add)
  useEffect(() => {
    if (!selectedStudent && students.length > 0) {
      setSelectedStudent(students[0].id);
    }
  }, [students]);

  useEffect(() => {
    if (students.length > 0) {
      startCamera();
    }
    return () => stopCamera();
  }, [students.length]);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCapturing(true);
      }
    } catch (err) {
      console.error("Camera error:", err);
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
    }
    setIsCapturing(false);
  };

  const captureFrame = async () => {
    if (!videoRef.current || !canvasRef.current || !selectedStudent) return;

    setIsAnalyzing(true);
    const context = canvasRef.current.getContext('2d');
    if (context) {
      context.drawImage(videoRef.current, 0, 0, 640, 480);
      const dataUrl = canvasRef.current.toDataURL('image/jpeg');
      const base64Data = dataUrl.split(',')[1];

      const result = await analyzeFaceExpression(base64Data);
      if (result) {
        setLastAnalysis(result);
        onResult(selectedStudent, result);
      }
    }
    setIsAnalyzing(false);
  };

  if (students.length === 0) {
    return (
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 p-12 text-center space-y-4">
        <div className="text-6xl">👤</div>
        <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">No Subjects Detected</h2>
        <p className="text-slate-500 dark:text-slate-400 max-w-xs mx-auto text-sm">
          Please add students to your class roster before starting the visual check-in system.
        </p>
      </div>
    );
  }

  return (
    <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 p-8 shadow-sm transition-colors duration-300">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
        <div className="space-y-6">
          <div className="relative rounded-2xl overflow-hidden bg-slate-900 aspect-video flex items-center justify-center border-4 border-slate-800 dark:border-slate-700 shadow-2xl">
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className="w-full h-full object-cover"
            />
            <canvas ref={canvasRef} width="640" height="480" className="hidden" />

            {isAnalyzing && (
              <div className="absolute inset-0 bg-indigo-900/60 backdrop-blur-sm flex flex-col items-center justify-center text-white p-6 text-center">
                <div className="w-12 h-12 border-4 border-white/20 border-t-white rounded-full animate-spin mb-4"></div>
                <p className="font-bold tracking-wide">AI Neural Analysis...</p>
                <p className="text-xs opacity-70 mt-2">Gauging sentiment markers via on-device processing</p>
              </div>
            )}

            {!isCapturing && !isAnalyzing && (
              <button 
                onClick={startCamera}
                className="bg-white text-slate-900 px-6 py-2 rounded-full font-bold shadow-lg hover:scale-105 active:scale-95 transition-all"
              >
                Reconnect Camera
              </button>
            )}
          </div>

          <div className="flex flex-col gap-4">
            {!isStudentView && (
              <>
                <label className="text-sm font-semibold text-slate-500 dark:text-slate-400">Assign Analysis To:</label>
                <select 
                  value={selectedStudent}
                  onChange={(e) => setSelectedStudent(e.target.value)}
                  className="w-full p-4 rounded-2xl border border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors"
                >
                  {students.map(s => (
                    <option key={s.id} value={s.id}>{s.name}</option>
                  ))}
                </select>
              </>
            )}

            <button
              onClick={captureFrame}
              disabled={isAnalyzing || !isCapturing}
              className={`w-full py-4 rounded-2xl font-bold text-white transition-all transform active:scale-95 ${
                isAnalyzing || !isCapturing 
                  ? 'bg-slate-300 dark:bg-slate-800' 
                  : isStudentView 
                    ? 'bg-emerald-600 hover:bg-emerald-700 shadow-xl shadow-emerald-200 dark:shadow-none'
                    : 'bg-indigo-600 hover:bg-indigo-700 shadow-xl shadow-indigo-200 dark:shadow-none'
              }`}
            >
              {isStudentView ? 'Personal Mood Check-in' : 'Capture Student Sentiment'}
            </button>
          </div>
        </div>

        <div className="flex flex-col justify-center">
          {lastAnalysis ? (
            <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-500">
              <div className="flex justify-between items-center">
                <h3 className="text-2xl font-bold text-slate-800 dark:text-slate-100">Live Insights</h3>
                <span className="text-indigo-600 dark:text-indigo-400 px-3 py-1 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl text-xs font-bold uppercase tracking-widest">
                  {Math.round(lastAnalysis.confidence * 100)}% Match
                </span>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 bg-slate-50 dark:bg-slate-950 rounded-2xl border border-slate-100 dark:border-slate-800">
                  <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Detected State</p>
                  <p className="text-xl font-bold text-slate-800 dark:text-slate-100">{lastAnalysis.emotion}</p>
                </div>
                <div className="p-4 bg-slate-50 dark:bg-slate-950 rounded-2xl border border-slate-100 dark:border-slate-800">
                  <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Engagement</p>
                  <p className={`text-xl font-bold ${
                    lastAnalysis.engagement === 'High' ? 'text-emerald-600' : 
                    lastAnalysis.engagement === 'Low' ? 'text-rose-600' : 'text-amber-600'
                  }`}>
                    {lastAnalysis.engagement}
                  </p>
                </div>
              </div>

              <div className="p-6 bg-slate-50 dark:bg-slate-950 rounded-2xl border border-slate-100 dark:border-slate-800">
                <div className="flex justify-between items-center mb-4">
                  <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase">Stress Marker</p>
                  <p className="text-2xl font-black text-indigo-600 dark:text-indigo-400">{lastAnalysis.stressScore}<span className="text-sm font-medium text-slate-400">/10</span></p>
                </div>
                <div className="w-full h-3 bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden">
                  <div 
                    className={`h-full transition-all duration-1000 ${
                      lastAnalysis.stressScore > 7 ? 'bg-rose-500' : 
                      lastAnalysis.stressScore > 4 ? 'bg-amber-500' : 'bg-emerald-500'
                    }`}
                    style={{ width: `${lastAnalysis.stressScore * 10}%` }}
                  />
                </div>
              </div>

              <div className="p-6 bg-indigo-50 dark:bg-indigo-900/20 rounded-2xl border border-indigo-100 dark:border-indigo-800/30">
                <p className="text-indigo-900 dark:text-indigo-300 font-medium leading-relaxed italic">
                  "{lastAnalysis.summary}"
                </p>
              </div>
            </div>
          ) : (
            <div className="text-center space-y-4 py-20 bg-slate-50 dark:bg-slate-950 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-800">
              <div className="text-6xl opacity-30">📷</div>
              <p className="text-slate-400 dark:text-slate-500 max-w-xs mx-auto text-sm">
                {isStudentView 
                  ? "Smile for the camera! This check-in helps you track your wellness journey."
                  : "Target a student's webcam feed and click capture to begin expression analysis."}
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default CaptureUI;

import React, { useState, useEffect } from 'react';
import { analyzeStudentJournal } from '../services/geminiService';
import { TextSentimentResult, StudentRecord } from '../types';

interface JournalUIProps {
  students: StudentRecord[];
  isStudentView?: boolean;
}

const JournalUI: React.FC<JournalUIProps> = ({ students, isStudentView }) => {
  const [journalText, setJournalText] = useState('');
  const [selectedStudent, setSelectedStudent] = useState(students[0]?.id || '');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<TextSentimentResult | null>(null);

  useEffect(() => {
    if (!selectedStudent && students.length > 0) {
      setSelectedStudent(students[0].id);
    }
  }, [students]);

  const handleAnalyze = async () => {
    if (!journalText.trim()) return;
    setIsAnalyzing(true);
    const analysis = await analyzeStudentJournal(journalText);
    if (analysis) {
      setResult(analysis);
    }
    setIsAnalyzing(false);
  };

  if (students.length === 0) {
    return (
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 p-12 text-center space-y-4">
        <div className="text-6xl">✍️</div>
        <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">Journal Unavailable</h2>
        <p className="text-slate-500 dark:text-slate-400 max-w-xs mx-auto text-sm">
          Sentiment analysis requires at least one registered student. Please add students in the roster tab.
        </p>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm transition-colors duration-300">
        <h2 className={`text-2xl font-bold mb-6 flex items-center gap-3 ${isStudentView ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-800 dark:text-slate-100'}`}>
          <span>✍️</span> {isStudentView ? 'My Reflection Journal' : 'Sentiment Analysis Engine'}
        </h2>

        <div className="space-y-6">
          {!isStudentView && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-500 dark:text-slate-400">Student Source:</label>
                <select 
                  value={selectedStudent}
                  onChange={(e) => setSelectedStudent(e.target.value)}
                  className="w-full p-3 rounded-xl border border-slate-200 dark:border-slate-800 outline-none focus:ring-2 focus:ring-indigo-500 bg-white dark:bg-slate-950 text-slate-800 dark:text-slate-100"
                >
                  {students.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>
            </div>
          )}

          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-500 dark:text-slate-400">
              {isStudentView ? 'How are you feeling today?' : 'Paste Reflection / Essay Segment:'}
            </label>
            <textarea
              value={journalText}
              onChange={(e) => setJournalText(e.target.value)}
              placeholder={isStudentView ? "Write down your thoughts about school, work, or anything on your mind..." : "e.g. I felt really overwhelmed today with the math project..."}
              className="w-full h-48 p-4 rounded-2xl border border-slate-200 dark:border-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none resize-none bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-100 transition-colors"
            />
          </div>

          <button
            onClick={handleAnalyze}
            disabled={isAnalyzing || !journalText.trim()}
            className={`w-full py-4 rounded-xl text-white font-bold transition-all disabled:opacity-50 flex items-center justify-center gap-2 shadow-lg ${
              isStudentView 
                ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-100 dark:shadow-none' 
                : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100 dark:shadow-none'
            }`}
          >
            {isAnalyzing ? (
              <><div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin" /> Processing Insights...</>
            ) : (
              isStudentView ? 'Submit Reflection' : 'Analyze Content'
