import React, { useState } from 'react';
import { StudentRecord } from '../types';

interface StatusMonitorProps {
  students: StudentRecord[];
}

const StatusMonitor: React.FC<StatusMonitorProps> = ({ students }) => {
  const [filter, setFilter] = useState<'all' | 'flagged'>('all');
  const [search, setSearch] = useState('');

  const filtered = students.filter(s => {
    const matchesFilter = filter === 'all' || s.isFlagged;
    const matchesSearch = s.name.toLowerCase().includes(search.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  const getStatusColor = (score: number) => {
    if (score >= 8) return 'bg-rose-500';
    if (score >= 5) return 'bg-amber-500';
    return 'bg-emerald-500';
  };

  const getStatusBg = (score: number) => {
    if (score >= 8) return 'bg-rose-50 dark:bg-rose-900/10 border-rose-100 dark:border-rose-900/30';
    if (score >= 5) return 'bg-amber-50 dark:bg-amber-900/10 border-amber-100 dark:border-amber-900/30';
    return 'bg-emerald-50 dark:bg-emerald-900/10 border-emerald-100 dark:border-emerald-900/30';
  };

  const getStatusText = (score: number) => {
    if (score >= 8) return 'text-rose-700 dark:text-rose-400';
    if (score >= 5) return 'text-amber-700 dark:text-amber-400';
    return 'text-emerald-700 dark:text-emerald-400';
  };

  if (students.length === 0) {
    return (
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 p-12 text-center space-y-4">
        <div className="text-6xl text-slate-300">🩺</div>
        <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">Monitor Unavailable</h2>
        <p className="text-slate-500 dark:text-slate-400 max-w-xs mx-auto text-sm">
          You need to add students to the roster before you can monitor their status.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-slate-100 tracking-tight">Status Monitor</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium italic">High-density view of student wellness markers.</p>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <input 
            type="text" 
            placeholder="Search student..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="px-4 py-2 rounded-xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-100 text-sm outline-none focus:ring-2 focus:ring-indigo-500 transition-all w-full md:w-64"
          />
          <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl border border-slate-200 dark:border-slate-700">
            <button 
              onClick={() => setFilter('all')}
              className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
                filter === 'all' ? 'bg-white dark:bg-slate-700 text-indigo-600 shadow-sm' : 'text-slate-500'
              }`}
            >
              All
            </button>
            <button 
              onClick={() => setFilter('flagged')}
              className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
                filter === 'flagged' ? 'bg-white dark:bg-slate-700 text-rose-600 shadow-sm' : 'text-slate-500'
              }`}
            >
              At Risk
            </button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {filtered.map(student => {
          const score = student.lastAnalysis?.stressScore || 0;
          return (
            <div key={student.id} className={`p-5 rounded-[2rem] border transition-all hover:shadow-lg ${getStatusBg(score)}`}>
              <div className="flex items-center gap-4 mb-4">
                <img src={student.avatar} className="w-12 h-12 rounded-2xl bg-white/50 dark:bg-black/20" alt={student.name} />
                <div className="flex-1 min-w-0">
                  <h3 className="font-bold text-slate-800 dark:text-slate-100 truncate">{student.name}</h3>
                  <div className="flex items-center gap-1.5">
                    <div className={`w-2 h-2 rounded-full ${getStatusColor(score)}`} />
                    <span className={`text-[10px] font-black uppercase tracking-widest ${getStatusText(score)}`}>
                      {score >= 8 ? 'Critical' : score >= 5 ? 'Warning' : 'Healthy'}
                    </span>
                  </div>
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex justify-between items-center text-xs">
                  <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-tighter">Emotion</span>
                  <span className="font-black text-slate-800 dark:text-slate-100">{student.lastAnalysis?.emotion || 'N/A'}</span>
                </div>
                <div className="flex justify-between items-center text-xs">
                  <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-tighter">Engagement</span>
                  <span className="font-black text-slate-800 dark:text-slate-100">{student.lastAnalysis?.engagement || 'N/A'}</span>
                </div>
                <div className="pt-2">
                  <div className="flex justify-between items-center mb-1">
                    <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase">Stress Intensity</span>
                    <span className="text-sm font-black text-slate-800 dark:text-slate-100">{score}/10</span>
                  </div>
                  <div className="w-full h-1.5 bg-white/50 dark:bg-black/20 rounded-full overflow-hidden">
                    <div className={`h-full ${getStatusColor(score)}`} style={{ width: `${score * 10}%` }} />
                  </div>
                </div>
              </div>

              {student.lastAnalysis?.summary && (
                <div className="mt-4 pt-4 border-t border-black/5 dark:border-white/5">
                  <p className="text-[10px] leading-relaxed text-slate-600 dark:text-slate-300 line-clamp-2 italic font-medium">
                    "{student.lastAnalysis.summary}"
                  </p>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {filtered.length === 0 && (
        <div className="py-20 text-center text-slate-400 font-bold uppercase tracking-widest text-sm italic">
          No students match your current filter.
        </div>
      )}
    </div>
  );
};

export default StatusMonitor;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import CaptureUI from './components/CaptureUI';
import JournalUI from './components/JournalUI';
import StudentRoster from './components/StudentRoster';
import Settings from './components/Settings';
import Login from './components/Login';
import StatusMonitor from './components/StatusMonitor';
import { StudentRecord, EmotionalAnalysis, EmotionType, EngagementLevel, UserRole } from './types';

const getAvatarUrl = (seed: string) => `https://api.dicebear.com/7.x/avataaars/svg?seed=${encodeURIComponent(seed)}`;

// Empty initialization as requested - teachers must add their own students
const INITIAL_STUDENTS: StudentRecord[] = [];

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(() => localStorage.getItem('isLoggedIn') === 'true');
  const [userRole, setUserRole] = useState<UserRole | null>(() => (localStorage.getItem('userRole') as UserRole) || null);
  const [currentStudentId, setCurrentStudentId] = useState<string | null>(() => localStorage.getItem('currentStudentId') || null);

  const [activeTab, setActiveTab] = useState<'dashboard' | 'capture' | 'roster' | 'journals' | 'settings' | 'status'>('dashboard');
  const [students, setStudents] = useState<StudentRecord[]>(() => {
    const saved = localStorage.getItem('students');
    return saved ? JSON.parse(saved) : INITIAL_STUDENTS;
  });
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('theme') as 'light' | 'dark') || 'light';
  });

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('students', JSON.stringify(students));
  }, [students]);

  const handleLogin = (role: UserRole, studentId?: string) => {
    setIsLoggedIn(true);
    setUserRole(role);
    localStorage.setItem('isLoggedIn', 'true');
    localStorage.setItem('userRole', role);
    if (studentId) {
      setCurrentStudentId(studentId);
      localStorage.setItem('currentStudentId', studentId);
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUserRole(null);
    setCurrentStudentId(null);
    localStorage.removeItem('isLoggedIn');
    localStorage.removeItem('userRole');
    localStorage.removeItem('currentStudentId');
  };

  const handleNewAnalysis = (studentId: string, analysis: EmotionalAnalysis) => {
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) {
        return {
          ...s,
          lastAnalysis: analysis,
          history: [...s.history, analysis],
          isFlagged: analysis.stressScore > 7 || analysis.emotion === EmotionType.FRUSTRATED
        };
      }
      return s;
    }));
  };

  const handleAddStudent = (name: string, customAvatar?: string) => {
    const newStudent: StudentRecord = {
      id: 's' + Math.random().toString(36).substr(2, 9),
      name,
      avatar: customAvatar || getAvatarUrl(name + Date.now()),
      history: [],
      isFlagged: false
    };
    setStudents(prev => [...prev, newStudent]);
  };

  const handleDeleteStudent = (id: string) => {
    setStudents(prev => prev.filter(s => s.id !== id));
  };

  const handleUpdateStudent = (id: string, updates: Partial<StudentRecord>) => {
    setStudents(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
  };

  if (!isLoggedIn) {
    return <Login onLogin={handleLogin} students={students} />;
  }

  const filteredStudentsForUI = userRole === UserRole.STUDENT && currentStudentId 
    ? students.filter(s => s.id === currentStudentId)
    : students;

  return (
    <div className="flex h-screen w-full overflow-hidden text-slate-900 dark:text-slate-100 transition-colors duration-300">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={handleLogout} 
        userRole={userRole!} 
      />

      <main className="flex-1 bg-[#f8fafc] dark:bg-slate-950 overflow-y-auto p-8 transition-colors duration-300">
        <div className="max-w-7xl mx-auto">
          {activeTab === 'dashboard' && <Dashboard students={filteredStudentsForUI} isStudentView={userRole === UserRole.STUDENT} />}
          {activeTab === 'status' && userRole === UserRole.TEACHER && <StatusMonitor students={students} />}
          {activeTab === 'capture' && userRole === UserRole.STUDENT && <CaptureUI students={filteredStudentsForUI} onResult={handleNewAnalysis} isStudentView={true} />}
          {activeTab === 'roster' && userRole === UserRole.TEACHER && (
            <StudentRoster 
              students={students} 
              onAddStudent={handleAddStudent} 
              onUpdateStudent={handleUpdateStudent}
              onDeleteStudent={handleDeleteStudent}
            />
          )}
          {activeTab === 'journals' && <JournalUI students={filteredStudentsForUI} isStudentView={userRole === UserRole.STUDENT} />}
          {activeTab === 'settings' && <Settings theme={theme} setTheme={setTheme} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';
import { analyzeFaceExpression } from '../services/geminiService';
import { EmotionalAnalysis, StudentRecord } from '../types';

interface CaptureUIProps {
  students: StudentRecord[];
  onResult: (studentId: string, analysis: EmotionalAnalysis) => void;
  isStudentView?: boolean;
}

const CaptureUI: React.FC<CaptureUIProps> = ({ students, onResult, isStudentView }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCapturing, setIsCapturing] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [lastAnalysis, setLastAnalysis] = useState<EmotionalAnalysis | null>(null);

  const student = students[0]; // In student view, there is only one student in the filtered list

  useEffect(() => {
    if (student) {
      startCamera();
    }
    return () => stopCamera();
  }, [student?.id]);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCapturing(true);
      }
    } catch (err) {
      console.error("Camera error:", err);
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
    }
    setIsCapturing(false);
  };

  const captureFrame = async () => {
    if (!videoRef.current || !canvasRef.current || !student) return;

    setIsAnalyzing(true);
    const context = canvasRef.current.getContext('2d');
    if (context) {
      context.drawImage(videoRef.current, 0, 0, 640, 480);
      const dataUrl = canvasRef.current.toDataURL('image/jpeg');
      const base64Data = dataUrl.split(',')[1];

      const result = await analyzeFaceExpression(base64Data);
      if (result) {
        setLastAnalysis(result);
        onResult(student.id, result);
      }
    }
    setIsAnalyzing(false);
  };

  if (!student) {
    return (
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 p-12 text-center space-y-4">
        <div className="text-6xl">👤</div>
        <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">Profile Not Found</h2>
        <p className="text-slate-500 dark:text-slate-400 max-w-xs mx-auto text-sm">
          Something went wrong. We couldn't find your student profile.
        </p>
      </div>
    );
  }

  return (
    <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 p-8 shadow-sm transition-colors duration-300">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
        <div className="space-y-6">
          <div className="relative rounded-[2.5rem] overflow-hidden bg-slate-900 aspect-video flex items-center justify-center border-4 border-emerald-500/20 dark:border-emerald-500/10 shadow-2xl">
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className="w-full h-full object-cover"
            />
            <canvas ref={canvasRef} width="640" height="480" className="hidden" />

            {isAnalyzing && (
              <div className="absolute inset-0 bg-emerald-900/60 backdrop-blur-md flex flex-col items-center justify-center text-white p-6 text-center">
                <div className="w-12 h-12 border-4 border-white/20 border-t-white rounded-full animate-spin mb-4"></div>
                <p className="font-bold tracking-wide">Analyzing Mindset...</p>
                <p className="text-xs opacity-70 mt-2">Personal sentiment check-in in progress</p>
              </div>
            )}

            {!isCapturing && !isAnalyzing && (
              <button 
                onClick={startCamera}
                className="bg-white text-slate-900 px-6 py-2 rounded-full font-bold shadow-lg hover:scale-105 active:scale-95 transition-all"
              >
                Start Camera
              </button>
            )}
          </div>

          <div className="flex flex-col gap-4 text-center">
            <div className="p-4 bg-emerald-50 dark:bg-emerald-900/10 rounded-2xl border border-emerald-100 dark:border-emerald-900/30">
              <p className="text-xs font-bold text-emerald-700 dark:text-emerald-400 uppercase tracking-widest mb-1">Self Check-in</p>
              <p className="text-sm text-slate-500 dark:text-slate-400 italic">"How are you feeling right now, {student.name}?"</p>
            </div>

            <button
              onClick={captureFrame}
              disabled={isAnalyzing || !isCapturing}
              className={`w-full py-5 rounded-3xl font-black text-white transition-all transform active:scale-95 shadow-xl ${
                isAnalyzing || !isCapturing 
                  ? 'bg-slate-300 dark:bg-slate-800 cursor-not-allowed' 
                  : 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200 dark:shadow-none'
              }`}
            >
              Perform Wellness Check
            </button>
          </div>
        </div>

        <div className="flex flex-col justify-center">
          {lastAnalysis ? (
            <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-500">
              <div className="flex justify-between items-center">
                <h3 className="text-2xl font-black text-slate-800 dark:text-slate-100">Your Insights</h3>
                <span className="text-emerald-600 dark:text-emerald-400 px-3 py-1 bg-emerald-50 dark:bg-emerald-900/30 rounded-xl text-xs font-bold uppercase tracking-widest">
                  Live Scan
                </span>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 bg-slate-50 dark:bg-slate-950 rounded-2xl border border-slate-100 dark:border-slate-800">
                  <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Sentiment</p>
                  <p className="text-xl font-bold text-slate-800 dark:text-slate-100">{lastAnalysis.emotion}</p>
                </div>
                <div className="p-4 bg-slate-50 dark:bg-slate-950 rounded-2xl border border-slate-100 dark:border-slate-800">
                  <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Flow State</p>
