interface SettingsProps {
  theme: 'light' | 'dark';
  setTheme: (theme: 'light' | 'dark') => void;
  userRole: UserRole;
  student?: StudentRecord | null;
  onUpdateStudent?: (id: string, updates: Partial<StudentRecord>) => void;
}

const Settings: React.FC<SettingsProps> = ({ theme, setTheme, userRole, student, onUpdateStudent }) => {
  const [isGenerating, setIsGenerating] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && student && onUpdateStudent) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onUpdateStudent(student.id, { avatar: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAIGen = async () => {
    if (student && onUpdateStudent) {
      setIsGenerating(true);
      const newAvatar = await generateAIAvatar(student.name);
      if (newAvatar) {
        onUpdateStudent(student.id, { avatar: newAvatar });
      }
      setIsGenerating(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div>
        <h2 className="text-3xl font-black text-slate-800 dark:text-slate-100">Preferences</h2>
        <p className="text-slate-500 dark:text-slate-400">Manage your workspace and personal identity.</p>
      </div>

      {userRole === UserRole.STUDENT && student && (
        <section className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm space-y-6">
