          <div className="flex flex-col md:flex-row items-center gap-8">
            <img src={student.avatar} className="w-32 h-32 rounded-[2.5rem] bg-slate-100 dark:bg-slate-800 shadow-xl border-4 border-white dark:border-slate-800" />
            <div className="flex-1 space-y-4 text-center md:text-left">
              <p className="text-slate-500 dark:text-slate-400 text-sm leading-relaxed">
                Choose how you appear to your teacher. You can upload a photo or generate a unique 3D stylized avatar using AI.
              </p>
              <div className="flex flex-wrap gap-2 justify-center md:justify-start">
                <button 
                  onClick={() => fileInputRef.current?.click()}
