import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import CaptureUI from './components/CaptureUI';
import JournalUI from './components/JournalUI';
import StudentRoster from './components/StudentRoster';
import Settings from './components/Settings';
import Login from './components/Login';
import StatusMonitor from './components/StatusMonitor';
import { StudentRecord, EmotionalAnalysis, EmotionType, EngagementLevel, UserRole } from './types';

const getAvatarUrl = (seed: string) => `https://api.dicebear.com/7.x/avataaars/svg?seed=${encodeURIComponent(seed)}`;

const INITIAL_STUDENTS: StudentRecord[] = [];

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(() => localStorage.getItem('isLoggedIn') === 'true');
  const [userRole, setUserRole] = useState<UserRole | null>(() => (localStorage.getItem('userRole') as UserRole) || null);
  const [currentStudentId, setCurrentStudentId] = useState<string | null>(() => localStorage.getItem('currentStudentId') || null);

  const [activeTab, setActiveTab] = useState<'dashboard' | 'capture' | 'roster' | 'journals' | 'settings' | 'status'>('dashboard');
  const [students, setStudents] = useState<StudentRecord[]>(() => {
    const saved = localStorage.getItem('students');
    return saved ? JSON.parse(saved) : INITIAL_STUDENTS;
  });
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('theme') as 'light' | 'dark') || 'light';
  });

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('students', JSON.stringify(students));
  }, [students]);

  const handleLogin = (role: UserRole, studentId?: string) => {
    setIsLoggedIn(true);
    setUserRole(role);
    localStorage.setItem('isLoggedIn', 'true');
    localStorage.setItem('userRole', role);
    if (studentId) {
      setCurrentStudentId(studentId);
      localStorage.setItem('currentStudentId', studentId);
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUserRole(null);
    setCurrentStudentId(null);
    localStorage.removeItem('isLoggedIn');
    localStorage.removeItem('userRole');
    localStorage.removeItem('currentStudentId');
  };

  const handleNewAnalysis = (studentId: string, analysis: EmotionalAnalysis) => {
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) {
        return {
          ...s,
          lastAnalysis: analysis,
          history: [...s.history, analysis],
          isFlagged: analysis.stressScore > 7 || analysis.emotion === EmotionType.FRUSTRATED
        };
      }
      return s;
    }));
  };

  const handleAddStudent = (name: string, customAvatar?: string) => {
    const newStudent: StudentRecord = {
      id: 's' + Math.random().toString(36).substr(2, 9),
      name,
      avatar: customAvatar || getAvatarUrl(name + Date.now()),
      history: [],
      isFlagged: false,
      feedback: []
    };
    setStudents(prev => [...prev, newStudent]);
  };

  const handleDeleteStudent = (id: string) => {
    setStudents(prev => prev.filter(s => s.id !== id));
  };

  const handleUpdateStudent = (id: string, updates: Partial<StudentRecord>) => {
    setStudents(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
  };

  const handleSendFeedback = (studentId: string, text: string) => {
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) {
        const newFeedback = {
          id: Math.random().toString(36).substr(2, 9),
          text,
          date: new Date().toLocaleString()
        };
        return { ...s, feedback: [newFeedback, ...(s.feedback || [])] };
      }
      return s;
    }));
  };

  if (!isLoggedIn) {
    return <Login onLogin={handleLogin} students={students} />;
  }

  const filteredStudentsForUI = userRole === UserRole.STUDENT && currentStudentId 
    ? students.filter(s => s.id === currentStudentId)
    : students;

  const currentStudent = currentStudentId ? students.find(s => s.id === currentStudentId) : null;

  return (
    <div className="flex h-screen w-full overflow-hidden text-slate-900 dark:text-slate-100 transition-colors duration-300">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={handleLogout} 
        userRole={userRole!} 
      />

      <main className="flex-1 bg-[#f8fafc] dark:bg-slate-950 overflow-y-auto p-8 transition-colors duration-300">
        <div className="max-w-7xl mx-auto">
          {activeTab === 'dashboard' && (
            <Dashboard 
              students={filteredStudentsForUI} 
              isStudentView={userRole === UserRole.STUDENT} 
              onSendFeedback={handleSendFeedback}
            />
          )}
          {activeTab === 'status' && userRole === UserRole.TEACHER && (
            <StatusMonitor 
              students={students} 
              onSendFeedback={handleSendFeedback} 
            />
          )}
          {activeTab === 'capture' && userRole === UserRole.STUDENT && <CaptureUI students={filteredStudentsForUI} onResult={handleNewAnalysis} isStudentView={true} />}
          {activeTab === 'roster' && userRole === UserRole.TEACHER && (
            <StudentRoster 
              students={students} 
              onAddStudent={handleAddStudent} 
              onUpdateStudent={handleUpdateStudent}
              onDeleteStudent={handleDeleteStudent}
            />
          )}
          {activeTab === 'journals' && userRole === UserRole.STUDENT && <JournalUI students={filteredStudentsForUI} isStudentView={true} />}
          {activeTab === 'settings' && (
            <Settings 
              theme={theme} 
              setTheme={setTheme} 
              userRole={userRole!}
              student={currentStudent}
              onUpdateStudent={handleUpdateStudent}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
