interface DashboardProps {
  students: StudentRecord[];
  isStudentView?: boolean;
  onSendFeedback?: (id: string, text: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ students, isStudentView, onSendFeedback }) => {
