import { StudentRecord } from "../types";

const STORAGE_KEY = 'sentient_learn_db_prod_v1';

export const storageService = {
  getStudents: (): StudentRecord[] => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (!saved) {
      return []; // Start empty as requested
    }
    try {
      return JSON.parse(saved);
    } catch (e) {
      console.error("Failed to parse stored students", e);
      return [];
    }
  },

  saveStudents: (students: StudentRecord[]) => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(students));
  },

  clearAll: () => {
    localStorage.removeItem(STORAGE_KEY);
  },

  exportToJSON: (students: StudentRecord[]) => {
    const dataStr = JSON.stringify(students, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);

    const exportFileDefaultName = `sentient_learn_backup_${new Date().toISOString().split('T')[0]}.json`;

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  },

  importFromJSON: (file: File): Promise<StudentRecord[]> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const json = JSON.parse(event.target?.result as string);
          if (Array.isArray(json)) {
            resolve(json);
          } else {
            reject(new Error("Invalid database format. Expected an array of students."));
          }
        } catch (e) {
          reject(e);
        }
      };
      reader.onerror = (error) => reject(error);
      reader.readAsText(file);
    });
  }
};

