  PieChart, Pie, Cell, AreaChart, Area 
} from 'recharts';
import { StudentRecord, EmotionType } from '../types';

interface DashboardProps {
  students: StudentRecord[];
  isStudentView?: boolean;
  onSendFeedback?: (id: string, text: string) => void;
  setActiveTab?: (tab: any) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ students, isStudentView, onSendFeedback, setActiveTab }) => {
  const [selectedStudentId, setSelectedStudentId] = useState<string>(students[0]?.id || '');
  const [feedbackTarget, setFeedbackTarget] = useState<StudentRecord | null>(null);
  const [feedbackText, setFeedbackText] = useState('');

  const COLORS = ['#10b981', '#6366f1', '#f59e0b', '#ef4444'];

  const selectedStudent = useMemo(() => 
    students.find(s => s.id === selectedStudentId) || students[0],
    [students, selectedStudentId]
  );

  const highStressStudents = useMemo(() => 
    students.filter(s => s.lastAnalysis && s.lastAnalysis.stressScore >= 7),
    [students]
  );

  const emotionData = useMemo(() => [
    { name: 'Happy', count: students.filter(s => s.lastAnalysis?.emotion === EmotionType.HAPPY).length },
    { name: 'Neutral', count: students.filter(s => s.lastAnalysis?.emotion === EmotionType.NEUTRAL).length },
    { name: 'Focused', count: students.filter(s => s.lastAnalysis?.engagement === 'High').length },
    { name: 'Concern', count: highStressStudents.length },
  ], [students, highStressStudents]);

  const trendData = useMemo(() => {
    if (isStudentView && selectedStudent?.history?.length > 0) {
      return selectedStudent.history.map((h, i) => ({ time: `Scan ${i + 1}`, value: h.stressScore }));
    }
    return [
      { time: 'T1', value: 0 }, { time: 'T2', value: 0 }, { time: 'T3', value: 0 }
    ];
  }, [isStudentView, selectedStudent]);

  const handleQuickFeedback = () => {
    if (feedbackTarget && feedbackText.trim() && onSendFeedback) {
      onSendFeedback(feedbackTarget.id, feedbackText.trim());
      setFeedbackText('');
      setFeedbackTarget(null);
    }
  };

  if (students.length === 0 && !isStudentView) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-8 text-center animate-in zoom-in-95 duration-500">
        <div className="text-9xl mb-4">🏫</div>
        <div className="space-y-4">
          <h2 className="text-4xl font-black text-slate-800 dark:text-slate-100 tracking-tight">Your Classroom is Empty</h2>
          <p className="text-slate-500 dark:text-slate-400 max-w-md mx-auto text-lg leading-relaxed">
            Start by adding students to your class roster or import a previously saved database backup.
          </p>
          <div className="flex flex-col sm:flex-row gap-4 justify-center pt-4">
            <button 
              onClick={() => setActiveTab && setActiveTab('roster')}
              className="px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-bold shadow-xl hover:bg-indigo-700 transition-all active:scale-95"
            >
              Go to Class Roster
            </button>
            <button 
              onClick={() => setActiveTab && setActiveTab('settings')}
              className="px-8 py-4 bg-white dark:bg-slate-900 text-indigo-600 dark:text-indigo-400 border border-indigo-100 dark:border-indigo-900 rounded-[2rem] font-bold shadow-md hover:bg-slate-50 transition-all active:scale-95"
            >
              Import Backup
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-slate-100 tracking-tight">
            {isStudentView ? `Welcome back, ${selectedStudent?.name}!` : 'Class Insight Engine'}
          </h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium italic">
            {isStudentView ? 'Monitoring your mindful learning journey.' : 'Real-time emotional monitoring for your active session.'}
          </p>
        </div>
      </div>

      {!isStudentView && highStressStudents.length > 0 && (
        <section className="bg-rose-50 dark:bg-rose-900/10 border border-rose-100 dark:border-rose-900/30 rounded-[2.5rem] p-8 animate-in fade-in slide-in-from-top-4 duration-500">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-rose-800 dark:text-rose-400 font-black uppercase tracking-widest text-sm flex items-center gap-2">
              <span>⚠️</span> Wellness Alert: High Stress Levels Detected
            </h3>
            <span className="px-3 py-1 bg-rose-600 text-white text-[10px] font-black rounded-full">
              {highStressStudents.length} CRITICAL
            </span>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {highStressStudents.map(s => (
              <div key={s.id} className="bg-white dark:bg-slate-900 p-5 rounded-[2rem] border border-rose-100 dark:border-rose-800/50 shadow-sm flex flex-col justify-between">
                <div className="flex items-center gap-4 mb-4">
                  <img src={s.avatar} className="w-12 h-12 rounded-2xl bg-slate-50" />
                  <div>
                    <h4 className="font-bold text-slate-800 dark:text-slate-100">{s.name}</h4>
                    <p className="text-xs font-black text-rose-600 uppercase">Stress Score: {s.lastAnalysis?.stressScore}/10</p>
                  </div>
                </div>
                <p className="text-xs text-slate-500 dark:text-slate-400 italic line-clamp-2 mb-4">
                  "{s.lastAnalysis?.summary}"
                </p>
                <button 
                  onClick={() => setFeedbackTarget(s)}
                  className="w-full py-2 bg-rose-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-700 transition-all shadow-lg shadow-rose-100 dark:shadow-none"
                >
                  Quick Respond
                </button>
              </div>
            ))}
          </div>
        </section>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] shadow-sm border border-slate-100 dark:border-slate-800">
            <h3 className="text-sm font-bold mb-6 text-slate-400 dark:text-slate-500 uppercase tracking-widest">
              {isStudentView ? 'My Wellness Progress' : 'Class Engagement Mix'}
            </h3>
            <div className="h-64">
              {isStudentView ? (
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={trendData}>
                    <defs>
                      <linearGradient id="colorArea" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <XAxis dataKey="time" hide />
                    <YAxis domain={[0, 10]} hide />
                    <Tooltip contentStyle={{ borderRadius: '16px', border: 'none' }} />
                    <Area type="monotone" dataKey="value" stroke="#10b981" fillOpacity={1} fill="url(#colorArea)" strokeWidth={4} />
                  </AreaChart>
                </ResponsiveContainer>
              ) : (
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={emotionData}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={80}
                      paddingAngle={5}
                      dataKey="count"
                    >
                      {emotionData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
              )}
            </div>
            {!isStudentView && (
              <div className="flex flex-wrap justify-center gap-4 mt-4">
                {emotionData.map((entry, index) => (
                  <div key={entry.name} className="flex items-center gap-1.5">
                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[index % COLORS.length] }} />
                    <span className="text-[10px] font-bold text-slate-400 uppercase">{entry.name}</span>
                  </div>
                ))}
              </div>
            )}
          </div>

          {isStudentView && (
            <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl shadow-indigo-200 dark:shadow-none relative overflow-hidden">
              <div className="relative z-10">
                <h3 className="text-sm font-bold uppercase tracking-widest opacity-80 mb-6 flex items-center gap-2">
                  <span>📬</span> Teacher Feedback
                </h3>
                {selectedStudent?.feedback && selectedStudent.feedback.length > 0 ? (
                  <div className="space-y-4">
                    {selectedStudent.feedback.slice(0, 2).map(msg => (
                      <div key={msg.id} className="bg-white/10 backdrop-blur-md p-5 rounded-2xl border border-white/20">
                        <p className="text-lg font-medium leading-relaxed italic">"{msg.text}"</p>
                        <p className="text-[10px] uppercase font-bold tracking-widest mt-2 text-white/60">{msg.date}</p>
                      </div>
                    ))}
                  </div>
                ) : (
                  <p className="text-white/60 italic">No feedback messages yet. Keep up the good work!</p>
                )}
              </div>
              <div className="absolute top-0 right-0 p-8 text-8xl opacity-10">💬</div>
            </div>
          )}
        </div>

        <div className="space-y-6">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 text-center">
            <img src={selectedStudent?.avatar} className="w-24 h-24 rounded-[2rem] mx-auto mb-4 border-4 border-indigo-50 shadow-xl" />
            <h4 className="font-black text-2xl dark:text-white">{selectedStudent?.name}</h4>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Status: Stable</p>

            <div className="grid grid-cols-2 gap-2 mt-6">
              <div className="p-3 bg-slate-50 dark:bg-slate-950 rounded-2xl">
                <p className="text-[10px] text-slate-400 uppercase font-bold">Emotion</p>
                <p className="font-bold text-indigo-600">{selectedStudent?.lastAnalysis?.emotion || '-'}</p>
              </div>
              <div className="p-3 bg-slate-50 dark:bg-slate-950 rounded-2xl">
                <p className="text-[10px] text-slate-400 uppercase font-bold">Stress</p>
                <p className="font-bold text-rose-600">{selectedStudent?.lastAnalysis?.stressScore || 0}</p>
              </div>
            </div>
          </div>

          <div className="bg-emerald-50 dark:bg-emerald-900/10 p-6 rounded-[2.5rem] border border-emerald-100 dark:border-emerald-800/30">
            <h5 className="text-[10px] font-black uppercase text-emerald-800 dark:text-emerald-400 tracking-widest mb-2">Engagement</h5>
            <p className="text-emerald-900 dark:text-emerald-200 text-xl font-bold">{selectedStudent?.lastAnalysis?.engagement || 'Unmeasured'}</p>
          </div>
        </div>
      </div>

      {feedbackTarget && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setFeedbackTarget(null)} />
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-md rounded-[2.5rem] shadow-2xl p-8 animate-in zoom-in-95 duration-300">
            <h3 className="text-xl font-bold mb-2 dark:text-white">Respond to {feedbackTarget.name}</h3>
            <p className="text-sm text-slate-500 dark:text-slate-400 mb-6">Send a reassuring message based on the recent alert.</p>

            <textarea
              autoFocus
              value={feedbackText}
              onChange={(e) => setFeedbackText(e.target.value)}
              placeholder="e.g. I noticed you might be feeling a bit overwhelmed. Would you like to take a 5-minute breather?"
              className="w-full h-32 p-4 rounded-2xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 text-slate-800 dark:text-slate-100 outline-none focus:ring-2 focus:ring-rose-500 transition-all resize-none mb-6"
            />

            <div className="flex gap-3">
              <button onClick={() => setFeedbackTarget(null)} className="flex-1 py-3 text-sm font-bold text-slate-500">Cancel</button>
              <button 
                onClick={handleQuickFeedback}
                disabled={!feedbackText.trim()}
                className="flex-1 py-3 bg-rose-600 text-white rounded-xl font-bold shadow-lg hover:bg-rose-700 disabled:opacity-50 transition-all"
              >
                Send Support
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

export enum UserRole {
  TEACHER = 'TEACHER',
  STUDENT = 'STUDENT'
}

export enum EmotionType {
  HAPPY = 'Happy',
  SAD = 'Sad',
  ANGRY = 'Angry',
  SURPRISED = 'Surprised',
  NEUTRAL = 'Neutral',
  CONFUSED = 'Confused',
  FRUSTRATED = 'Frustrated',
  ANXIOUS = 'Anxious'
}

export enum EngagementLevel {
  HIGH = 'High',
  MEDIUM = 'Medium',
  LOW = 'Low'
}

export interface Feedback {
  id: string;
  text: string;
  date: string;
}

export interface ChatMessage {
  id: string;
  senderId: string;
  text: string;
  timestamp: string;
}

export interface Conversation {
  participantId: string;
  status: 'pending' | 'accepted' | 'rejected';
  messages: ChatMessage[];
}

export interface EmotionalAnalysis {
  emotion: EmotionType;
  engagement: EngagementLevel;
  stressScore: number; // 0-10
  confidence: number;
  summary: string;
}

export interface StudentRecord {
  id: string;
  name: string;
  avatar: string;
  lastAnalysis?: EmotionalAnalysis;
  history: EmotionalAnalysis[];
  isFlagged: boolean;
  feedback?: Feedback[];
  conversations?: Conversation[]; // Peer chats
}

export interface TextSentimentResult {
  sentiment: string;
  stressScore: number;
  keywords: string[];
  interventionRecommended: boolean;
  analysis: string;
}

import React from 'react';
import { UserRole } from '../types';

interface SidebarProps {
  activeTab: 'dashboard' | 'capture' | 'roster' | 'journals' | 'settings' | 'status' | 'chat';
  setActiveTab: (tab: 'dashboard' | 'capture' | 'roster' | 'journals' | 'settings' | 'status' | 'chat') => void;
  onLogout: () => void;
  userRole: UserRole;
}

const Sidebar: React.FC<SidebarProps> = ({ activeTab, setActiveTab, onLogout, userRole }) => {
  const allTabs = [
    { id: 'dashboard', label: userRole === UserRole.TEACHER ? 'Overview' : 'My Progress', icon: '📊', roles: [UserRole.TEACHER, UserRole.STUDENT] },
    { id: 'status', label: 'Status Monitor', icon: '🩺', roles: [UserRole.TEACHER] },
    { id: 'roster', label: 'Class Roster', icon: '👥', roles: [UserRole.TEACHER] },
    { id: 'capture', label: 'Visual Check-in', icon: '📷', roles: [UserRole.STUDENT] },
    { id: 'journals', label: 'Journal Analysis', icon: '✍️', roles: [UserRole.STUDENT] },
    { id: 'chat', label: 'Peer Chat', icon: '💬', roles: [UserRole.STUDENT] },
    { id: 'settings', label: 'Settings', icon: '⚙️', roles: [UserRole.TEACHER, UserRole.STUDENT] },
  ];

  const filteredTabs = allTabs.filter(tab => tab.roles.includes(userRole));

  return (
    <div className="w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 flex flex-col h-full transition-colors duration-300">
      <div className="p-6">
        <h1 className="text-2xl font-bold text-indigo-600 dark:text-indigo-400 flex items-center gap-2">
          <span className="text-3xl">🧠</span> SentientLearn
        </h1>
        <p className="text-[10px] text-slate-400 mt-1 uppercase tracking-widest font-bold">
          {userRole === UserRole.TEACHER ? 'Teacher Portal' : 'Student Portal'}
        </p>
      </div>

      <nav className="flex-1 px-4 space-y-1">
        {filteredTabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
              activeTab === tab.id
                ? userRole === UserRole.TEACHER 
                  ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 font-semibold'
                  : 'bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 font-semibold'
                : 'text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800/50'
            }`}
          >
            <span className="text-xl">{tab.icon}</span>
            {tab.label}
          </button>
        ))}
      </nav>

      <div className="p-4 mt-auto border-t border-slate-100 dark:border-slate-800 space-y-2">
        <button 
          onClick={onLogout}
          className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-rose-600 dark:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/20 transition-all font-semibold"
        >
          <span className="text-xl">🚪</span> Logout
        </button>
        <div className="text-center">
          <p className="text-[10px] text-slate-400 font-medium">© 2025 SentientLearn Analytics</p>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { StudentRecord, Conversation, ChatMessage } from '../types';

interface StudentChatProps {
  currentStudent: StudentRecord;
  allStudents: StudentRecord[];
  onSendRequest: (targetId: string) => void;
  onRespondRequest: (targetId: string, accept: boolean) => void;
  onSendMessage: (targetId: string, text: string) => void;
}

const StudentChat: React.FC<StudentChatProps> = ({ 
  currentStudent, 
  allStudents, 
  onSendRequest, 
  onRespondRequest, 
  onSendMessage 
}) => {
  const [activeChatId, setActiveChatId] = useState<string | null>(null);
  const [msgInput, setMsgInput] = useState('');

  const otherStudents = allStudents.filter(s => s.id !== currentStudent.id);

  const conversations = currentStudent.conversations || [];
  const activeConversation = conversations.find(c => c.participantId === activeChatId);
  const targetStudent = allStudents.find(s => s.id === activeChatId);

  const getConvStatus = (id: string) => {
    return conversations.find(c => c.participantId === id);
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if (activeChatId && msgInput.trim()) {
      onSendMessage(activeChatId, msgInput.trim());
      setMsgInput('');
    }
  };

  return (
    <div className="flex h-[calc(100vh-160px)] bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden">
      {/* Sidebar: List of Peers */}
      <div className="w-80 border-r border-slate-100 dark:border-slate-800 flex flex-col">
        <div className="p-6 border-b border-slate-50 dark:border-slate-800/50">
          <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100">Study Groups</h3>
          <p className="text-xs text-slate-400 uppercase font-black tracking-widest mt-1">Connect with Peers</p>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-2">
          {otherStudents.map(s => {
            const conv = getConvStatus(s.id);
            return (
              <button
                key={s.id}
                onClick={() => setActiveChatId(s.id)}
                className={`w-full flex items-center gap-3 p-3 rounded-2xl transition-all ${
                  activeChatId === s.id 
                    ? 'bg-emerald-50 dark:bg-emerald-900/30 border border-emerald-100 dark:border-emerald-800' 
                    : 'hover:bg-slate-50 dark:hover:bg-slate-800/50 border border-transparent'
                }`}
              >
                <div className="relative">
                  <img src={s.avatar} className="w-10 h-10 rounded-xl" alt={s.name} />
                  {conv?.status === 'accepted' && (
                    <div className="absolute -bottom-1 -right-1 w-3 h-3 bg-emerald-500 border-2 border-white dark:border-slate-900 rounded-full" />
                  )}
                </div>
                <div className="text-left flex-1 min-w-0">
                  <p className="font-bold text-sm text-slate-800 dark:text-slate-100 truncate">{s.name}</p>
                  <p className="text-[10px] uppercase font-black tracking-tighter text-slate-400">
                    {conv ? conv.status : 'No Connection'}
                  </p>
                </div>
              </button>
            );
          })}
        </div>
      </div>

      {/* Main Chat Area */}
      <div className="flex-1 flex flex-col bg-slate-50/30 dark:bg-slate-950/20">
        {targetStudent ? (
          <>
            {/* Header */}
            <div className="p-6 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <div className="flex items-center gap-4">
                <img src={targetStudent.avatar} className="w-12 h-12 rounded-2xl" alt={targetStudent.name} />
                <div>
                  <h4 className="font-bold text-slate-800 dark:text-slate-100">{targetStudent.name}</h4>
                  <p className="text-xs text-slate-500">Student Peer</p>
                </div>
              </div>
            </div>

            {/* Chat Content */}
            <div className="flex-1 overflow-y-auto p-6 space-y-4">
              {activeConversation?.status === 'pending' ? (
                <div className="h-full flex flex-col items-center justify-center text-center space-y-6">
                  <div className="text-6xl animate-bounce">⏳</div>
                  <div className="space-y-2 max-w-xs">
                    <h3 className="text-xl font-bold dark:text-white">Request Pending</h3>
                    <p className="text-sm text-slate-500">You need to wait for {targetStudent.name} to accept your chat request.</p>
                  </div>
                </div>
              ) : activeConversation?.status === 'accepted' ? (
                <>
                  {activeConversation.messages.map((m, idx) => {
                    const isMe = m.senderId === currentStudent.id;
                    return (
                      <div key={m.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[70%] p-4 rounded-3xl text-sm font-medium shadow-sm ${
                          isMe 
                            ? 'bg-emerald-600 text-white rounded-tr-none' 
                            : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 rounded-tl-none border border-slate-100 dark:border-slate-700'
                        }`}>
                          {m.text}
                          <p className={`text-[9px] mt-1 opacity-60 ${isMe ? 'text-right' : 'text-left'}`}>
                            {m.timestamp}
                          </p>
                        </div>
                      </div>
                    );
                  })}
                  {activeConversation.messages.length === 0 && (
                    <div className="text-center py-10 opacity-30 italic text-sm">
                      Connection established. Say hi!
                    </div>
                  )}
                </>
              ) : activeConversation?.status === 'rejected' ? (
                <div className="h-full flex flex-col items-center justify-center text-center p-8">
                  <div className="text-6xl mb-4">🚫</div>
                  <p className="text-slate-500 font-bold">The chat request was declined.</p>
                </div>
              ) : (
                /* No conversation yet - Send Request UI */
                <div className="h-full flex flex-col items-center justify-center text-center space-y-8 animate-in zoom-in-95">
                  <div className="text-7xl">🤝</div>
                  <div className="space-y-4">
                    <h3 className="text-2xl font-black dark:text-white">Start a Conversation</h3>
                    <p className="text-slate-500 max-w-xs">Connecting with your peers can help reduce stress and improve collaborative learning.</p>
                    <button 
                      onClick={() => onSendRequest(targetStudent.id)}
                      className="px-8 py-3 bg-emerald-600 text-white font-black rounded-2xl shadow-xl shadow-emerald-100 dark:shadow-none hover:bg-emerald-700 transition-all active:scale-95"
                    >
                      Send Chat Request
                    </button>
                  </div>
                </div>
              )}

              {/* Incoming Request Notification */}
              {/* Check if the OTHER person sent a request to ME that is still pending */}
              {(() => {
                const targetConvAtTarget = targetStudent.conversations?.find(c => c.participantId === currentStudent.id);
                const myConvAtMe = currentStudent.conversations?.find(c => c.participantId === targetStudent.id);

                // If I have a pending conversation where I'm the receiver...
                // Actually, simple way: if status is 'pending' and I am NOT the one who initiated? 
                // Let's rely on the logic in App.tsx that marks them as pending for both.
                // If currentStudent has a pending record with target, it could be inbound or outbound.
                // We'll simplify: if it's pending, and there are NO messages, show Accept/Reject.
              })()}

              {/* Special Handler for Incoming Pending */}
              {activeConversation?.status === 'pending' && (
                <div className="bg-emerald-50 dark:bg-emerald-900/20 p-6 rounded-3xl border border-emerald-100 dark:border-emerald-800 flex flex-col items-center gap-4">
                  <p className="text-sm font-bold text-emerald-800 dark:text-emerald-300">New Connection Request</p>
                  <div className="flex gap-2 w-full">
                    <button 
                      onClick={() => onRespondRequest(targetStudent.id, true)}
                      className="flex-1 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700"
                    >
                      Accept
                    </button>
                    <button 
                      onClick={() => onRespondRequest(targetStudent.id, false)}
                      className="flex-1 py-3 bg-white dark:bg-slate-800 text-rose-600 rounded-xl font-bold border border-rose-100 dark:border-rose-900"
                    >
                      Decline
                    </button>
                  </div>
                </div>
              )}
            </div>

            {/* Input Bar */}
            {activeConversation?.status === 'accepted' && (
              <form onSubmit={handleSend} className="p-6 bg-white dark:bg-slate-900 border-t border-slate-100 dark:border-slate-800 flex gap-4">
                <input 
                  type="text" 
                  value={msgInput}
                  onChange={(e) => setMsgInput(e.target.value)}
                  placeholder="Type your message..."
                  className="flex-1 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl px-6 outline-none focus:ring-2 focus:ring-emerald-500 dark:text-white"
                />
                <button 
                  type="submit"
                  disabled={!msgInput.trim()}
                  className="w-12 h-12 flex items-center justify-center bg-emerald-600 text-white rounded-2xl shadow-lg hover:bg-emerald-700 disabled:opacity-50 transition-all active:scale-95"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 rotate-90" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                  </svg>
                </button>
              </form>
            )}
          </>
        ) : (
          <div className="h-full flex flex-col items-center justify-center text-center p-12 space-y-6">
            <div className="text-9xl opacity-10">💬</div>
