import { GoogleGenAI, Type } from "@google/genai";
import { EmotionalAnalysis, TextSentimentResult } from "../types";

/**
 * Analyzes a student's facial expression using Gemini 3 Flash.
 * @param base64Image Base64 encoded JPEG image of the student.
 * @returns EmotionalAnalysis object or null on error.
 */
export const analyzeFaceExpression = async (base64Image: string): Promise<EmotionalAnalysis | null> => {
  // Always initialize a new instance to ensure the latest API key is used
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image,
            },
          },
          {
            text: "Analyze this student's facial expression for an emotional analytics platform. Determine their primary emotion, engagement level with schoolwork, stress score (0-10), and a brief summary.",
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            emotion: { type: Type.STRING, description: "One of: Happy, Sad, Angry, Surprised, Neutral, Confused, Frustrated, Anxious" },
            engagement: { type: Type.STRING, description: "One of: High, Medium, Low" },
            stressScore: { type: Type.NUMBER, description: "Scale from 0 (relaxed) to 10 (highly stressed)" },
            confidence: { type: Type.NUMBER, description: "Confidence score 0 to 1" },
            summary: { type: Type.STRING, description: "A one-sentence summary of the visual cues observed." },
          },
          required: ["emotion", "engagement", "stressScore", "confidence", "summary"],
        },
      },
    });

    // Access the text property directly from the GenerateContentResponse object
    const result = JSON.parse(response.text || '{}');
    return result as EmotionalAnalysis;
  } catch (error) {
    console.error("Gemini Image Analysis Error:", error);
    return null;
  }
};

/**
 * Analyzes a student's journal entry for sentiment and stress markers.
 * @param text The student's journal entry text.
 * @returns TextSentimentResult or null on error.
 */
export const analyzeStudentJournal = async (text: string): Promise<TextSentimentResult | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze the following student reflection or journal entry for emotional health and engagement markers: "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sentiment: { type: Type.STRING },
            stressScore: { type: Type.NUMBER },
            keywords: { 
                type: Type.ARRAY,
                items: { type: Type.STRING }
            },
            interventionRecommended: { type: Type.BOOLEAN },
            analysis: { type: Type.STRING, description: "Contextual reasoning for the analysis." },
          },
          required: ["sentiment", "stressScore", "keywords", "interventionRecommended", "analysis"],
        },
      },
    });

    // Directly access text property from the response
    const result = JSON.parse(response.text || '{}');
    return result as TextSentimentResult;
  } catch (error) {
    console.error("Gemini Text Analysis Error:", error);
    return null;
  }
};

/**
 * Generates a stylized AI avatar for a student.
 * @param studentName The name of the student.
 * @returns Base64 image URL or null on error.
 */
export const generateAIAvatar = async (studentName: string): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: `Create a stylized, friendly, 3D clay-style avatar of a student named ${studentName}. Minimal vector aesthetic, soft lighting, vibrant colors, solid pastel background. Head and shoulders only.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
        }
      },
    });

    // Iterate through candidates and parts to extract the inline image data
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini Image Generation Error:", error);
    return null;
  }
};

export enum UserRole {
  TEACHER = 'TEACHER',
  STUDENT = 'STUDENT'
}

export enum EmotionType {
  HAPPY = 'Happy',
  SAD = 'Sad',
  ANGRY = 'Angry',
  SURPRISED = 'Surprised',
  NEUTRAL = 'Neutral',
  CONFUSED = 'Confused',
  FRUSTRATED = 'Frustrated',
  ANXIOUS = 'Anxious'
}

export enum EngagementLevel {
  HIGH = 'High',
  MEDIUM = 'Medium',
  LOW = 'Low'
}

export interface Feedback {
  id: string;
  text: string;
  date: string;
}

export interface ChatMessage {
  id: string;
  senderId: string;
  text: string;
  timestamp: string;
}

export interface Conversation {
  participantId: string;
  initiatorId: string; // Tracks who sent the initial request
  status: 'pending' | 'accepted' | 'rejected';
  messages: ChatMessage[];
}

export interface EmotionalAnalysis {
  emotion: EmotionType;
  engagement: EngagementLevel;
  stressScore: number; // 0-10
  confidence: number;
  summary: string;
}

export interface StudentRecord {
  id: string;
  name: string;
  avatar: string;
  lastAnalysis?: EmotionalAnalysis;
  history: EmotionalAnalysis[];
  isFlagged: boolean;
  feedback?: Feedback[];
  conversations?: Conversation[]; // Peer chats
}

export interface TextSentimentResult {
  sentiment: string;
  stressScore: number;
  keywords: string[];
  interventionRecommended: boolean;
