import { StudentRecord } from "../types";

const PRIMARY_KEY = 'slp_classroom_primary_v2';
const BACKUP_KEY = 'slp_classroom_failsafe_v2';

export const storageService = {
  getStudents: (): StudentRecord[] => {
    // Attempt to load from primary
    const primarySaved = localStorage.getItem(PRIMARY_KEY);

    if (!primarySaved) {
      // Primary is empty, check failsafe backup
      const backupSaved = localStorage.getItem(BACKUP_KEY);
      if (backupSaved) {
        console.warn("Primary storage was empty. Auto-restored from failsafe backup.");
        // Restore primary from backup immediately
        localStorage.setItem(PRIMARY_KEY, backupSaved);
        return JSON.parse(backupSaved);
      }
      return []; 
    }

    try {
      const data = JSON.parse(primarySaved);
      // Ensure we keep the backup in sync whenever we successfully read
      localStorage.setItem(BACKUP_KEY, primarySaved);
      return data;
    } catch (e) {
      console.error("Failed to parse stored students, checking backup...", e);
      const backupSaved = localStorage.getItem(BACKUP_KEY);
      if (backupSaved) {
        return JSON.parse(backupSaved);
      }
      return [];
    }
  },

  saveStudents: (students: StudentRecord[]) => {
    const dataStr = JSON.stringify(students);
    try {
      localStorage.setItem(PRIMARY_KEY, dataStr);
      // Failsafe backup update
      localStorage.setItem(BACKUP_KEY, dataStr);
    } catch (e) {
      console.error("Storage error:", e);
      // If primary fails (e.g. quota exceeded), we still try backup or alert user
    }
  },

  clearAll: () => {
    localStorage.removeItem(PRIMARY_KEY);
    localStorage.removeItem(BACKUP_KEY);
  },

  exportToJSON: (students: StudentRecord[]) => {
    const dataStr = JSON.stringify(students, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);

    const exportFileDefaultName = `slp_database_backup_${new Date().toISOString().split('T')[0]}.json`;

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  },

  importFromJSON: (file: File): Promise<StudentRecord[]> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const json = JSON.parse(event.target?.result as string);
          if (Array.isArray(json)) {
            // After import, immediately save to both keys
            storageService.saveStudents(json);
            resolve(json);
          } else {
            reject(new Error("Invalid database format. Expected an array of students."));
          }
        } catch (e) {
          reject(e);
        }
      };
      reader.onerror = (error) => reject(error);
      reader.readAsText(file);
    });
  }
};

