import { StudentRecord } from "../types";

const BASE_PRIMARY = 'slp_classroom_primary_v4';
const BASE_BACKUP = 'slp_classroom_failsafe_v4';
const BASE_SNAPSHOT = 'slp_classroom_snapshot_v4';

const getKeys = (email: string) => {
  const sanitized = email.replace(/[^a-zA-Z0-9]/g, '_').toLowerCase();
  return {
    primary: `${BASE_PRIMARY}_${sanitized}`,
    backup: `${BASE_BACKUP}_${sanitized}`,
    snapshot: `${BASE_SNAPSHOT}_${sanitized}`
  };
};

export const storageService = {
  getStudents: (email: string): StudentRecord[] => {
    if (!email) return [];
    const keys = getKeys(email);

    try {
      // 1. Try Primary
      const primary = localStorage.getItem(keys.primary);
      if (primary) {
        const data = JSON.parse(primary);
        if (Array.isArray(data) && data.length > 0) return data;
      }

      // 2. Try Failsafe
      const backup = localStorage.getItem(keys.backup);
      if (backup) {
        console.warn(`Restoring ${email} from Failsafe.`);
        const data = JSON.parse(backup);
        if (Array.isArray(data) && data.length > 0) {
          localStorage.setItem(keys.primary, backup);
          return data;
        }
      }

      // 3. Try Gold Snapshot
      const snapshot = localStorage.getItem(keys.snapshot);
      if (snapshot) {
        console.error(`Emergency recovery for ${email} from Snapshot.`);
        const data = JSON.parse(snapshot);
        localStorage.setItem(keys.primary, snapshot);
        localStorage.setItem(keys.backup, snapshot);
        return data;
      }
    } catch (e) {
      console.error("Namespace retrieval failed:", e);
    }
    return [];
  },

  saveStudents: (email: string, students: StudentRecord[], forceWipe: boolean = false) => {
    if (!email || !Array.isArray(students)) return;
    const keys = getKeys(email);
    const dataStr = JSON.stringify(students);

    // Poisoning protection
    if (students.length === 0 && !forceWipe) {
      const existingBackup = localStorage.getItem(keys.backup);
      if (existingBackup && JSON.parse(existingBackup).length > 0) {
        return;
      }
    }

    try {
      localStorage.setItem(keys.primary, dataStr);
      if (students.length > 0 || forceWipe) {
        localStorage.setItem(keys.backup, dataStr);
      }
      if (students.length > 2) {
        localStorage.setItem(keys.snapshot, dataStr);
      }
    } catch (e) {
      console.error("Auto-save failed:", e);
    }
  },

  clearAllForUser: (email: string) => {
    if (!email) return;
    const keys = getKeys(email);
    localStorage.removeItem(keys.primary);
    localStorage.removeItem(keys.backup);
    localStorage.removeItem(keys.snapshot);
  },

  exportToJSON: (students: StudentRecord[], email: string) => {
    const dataStr = JSON.stringify(students, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    const filename = `slp_backup_${email}_${new Date().toISOString().split('T')[0]}.json`;
    const link = document.createElement('a');
    link.setAttribute('href', dataUri);
    link.setAttribute('download', filename);
    link.click();
  },

  importFromJSON: (file: File, email: string): Promise<StudentRecord[]> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const json = JSON.parse(event.target?.result as string);
          if (Array.isArray(json)) {
            storageService.saveStudents(email, json, true);
            resolve(json);
          } else {
            reject(new Error("Invalid format."));
          }
        } catch (e) {
          reject(e);
        }
      };
      reader.readAsText(file);
    });
  }
};

