import React, { useState } from 'react';
import { StudentRecord } from '../types';

interface StudentRosterProps {
  students: StudentRecord[];
  onAddStudent: (name: string, customAvatar?: string) => void;
  onUpdateStudent: (id: string, updates: Partial<StudentRecord>) => void;
  onDeleteStudent: (id: string) => void;
  onSendFeedback: (id: string, text: string) => void;
}

const StudentRoster: React.FC<StudentRosterProps> = ({ students, onAddStudent, onDeleteStudent, onSendFeedback }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newStudentName, setNewStudentName] = useState('');
  const [searchQuery, setSearchQuery] = useState('');

  // Feedback states
  const [feedbackTarget, setFeedbackTarget] = useState<StudentRecord | null>(null);
  const [feedbackText, setFeedbackText] = useState('');

  const filteredStudents = students.filter(s => 
    s.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newStudentName.trim()) {
      onAddStudent(newStudentName.trim());
      setNewStudentName('');
      setIsModalOpen(false);
    }
  };

  const confirmDelete = (student: StudentRecord) => {
    if (window.confirm(`Are you sure you want to remove ${student.name}? All historical emotional data will be permanently deleted.`)) {
      onDeleteStudent(student.id);
    }
  };

  const handleSendFeedback = () => {
    if (feedbackTarget && feedbackText.trim()) {
      onSendFeedback(feedbackTarget.id, feedbackText.trim());
      setFeedbackText('');
      setFeedbackTarget(null);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 dark:text-slate-100">Class Roster</h2>
          <p className="text-slate-500 dark:text-slate-400 text-sm">{students.length} Students Enrolled</p>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <input 
            type="text" 
            placeholder="Search students..." 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-800 outline-none focus:ring-2 focus:ring-indigo-500 bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-200 transition-all shadow-sm md:w-64"
          />
          <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg active:scale-95 whitespace-nowrap"
          >
            <span className="text-xl">+</span>
            <span>Add Student</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {filteredStudents.map((student) => (
          <div 
            key={student.id} 
            className={`bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] border transition-all hover:shadow-xl group relative ${
