              title="Remove Student"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
              </svg>
            </button>

            <div className="flex items-center gap-4 mb-6">
              <img src={student.avatar} className="w-16 h-16 rounded-2xl bg-slate-100 dark:bg-slate-800 object-cover shadow-inner" alt={student.name} />
              <div>
                <h3 className="font-bold text-slate-800 dark:text-slate-100 text-lg">{student.name}</h3>
                <p className="text-xs text-slate-500 dark:text-slate-400 font-mono tracking-tighter uppercase">ID: {student.id}</p>
              </div>
            </div>

            <div className="space-y-3 bg-slate-50 dark:bg-slate-950 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 mb-4">
              <div className="flex justify-between text-xs">
                <span className="text-slate-500 dark:text-slate-400 uppercase font-bold tracking-wider">Engagement</span>
                <span className="font-bold text-slate-800 dark:text-slate-100">{student.lastAnalysis?.engagement || 'None'}</span>
              </div>
              <div className="flex justify-between text-xs">
                <span className="text-slate-500 dark:text-slate-400 uppercase font-bold tracking-wider">Alert Status</span>
                <span className={`font-bold ${student.isFlagged ? 'text-rose-600' : 'text-emerald-600'}`}>
                  {student.isFlagged ? 'Flagged' : 'Healthy'}
                </span>
              </div>
            </div>

            <button 
              onClick={() => setFeedbackTarget(student)}
              className="w-full py-3 rounded-xl border-2 border-indigo-100 dark:border-indigo-900/50 text-indigo-600 dark:text-indigo-400 font-bold text-sm hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-all flex items-center justify-center gap-2 active:scale-95"
            >
              <span>💬</span> Provide Feedback
            </button>
          </div>
        ))}
      </div>

      {/* Enroll Student Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsModalOpen(false)} />
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-md rounded-[2.5rem] shadow-2xl p-8 animate-in zoom-in-95 duration-300">
            <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100 mb-6">Enroll Student</h3>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Full Name</label>
                <input 
                  type="text" 
                  autoFocus
                  required
                  value={newStudentName}
                  onChange={(e) => setNewStudentName(e.target.value)}
                  placeholder="e.g. John Doe"
                  className="w-full p-4 rounded-2xl border border-slate-200 dark:border-slate-800 outline-none focus:ring-2 focus:ring-indigo-500 bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-100"
                />
              </div>
              <div className="flex gap-3">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 font-bold text-slate-500">Cancel</button>
                <button type="submit" className="flex-1 py-4 rounded-2xl bg-indigo-600 text-white font-bold hover:bg-indigo-700 shadow-lg transition-all active:scale-95">Enlist</button>
              </div>
