import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import CaptureUI from './components/CaptureUI';
import JournalUI from './components/JournalUI';
import StudentRoster from './components/StudentRoster';
import Settings from './components/Settings';
import Login from './components/Login';
import StatusMonitor from './components/StatusMonitor';
import StudentChat from './components/StudentChat';
import { storageService } from './services/storageService';
import { StudentRecord, EmotionalAnalysis, UserRole, ChatMessage, Conversation } from './types';

const getAvatarUrl = (seed: string) => `https://api.dicebear.com/7.x/avataaars/svg?seed=${encodeURIComponent(seed)}`;

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(() => localStorage.getItem('isLoggedIn') === 'true');
  const [userRole, setUserRole] = useState<UserRole | null>(() => (localStorage.getItem('userRole') as UserRole) || null);
  const [userEmail, setUserEmail] = useState<string>(() => localStorage.getItem('userEmail') || '');
  const [currentStudentId, setCurrentStudentId] = useState<string | null>(() => localStorage.getItem('currentStudentId') || null);

  const [activeTab, setActiveTab] = useState<'dashboard' | 'capture' | 'roster' | 'journals' | 'settings' | 'status' | 'chat'>('dashboard');

  const [students, setStudents] = useState<StudentRecord[]>([]);
  const [isInitialized, setIsInitialized] = useState(false);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('theme') as 'light' | 'dark') || 'light';
  });

  // Re-hydrate data whenever identity (email) changes or app boots
  useEffect(() => {
    if (userEmail) {
      const savedData = storageService.getStudents(userEmail);
      setStudents(savedData);
      setIsInitialized(true);
    } else {
      // If not logged in, we might still want to see whatever was last active for student view
      const lastEmail = localStorage.getItem('userEmail');
      if (lastEmail) {
        setStudents(storageService.getStudents(lastEmail));
      }
    }
  }, [userEmail]);

  // Handle global theme
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  // Sync state to namespaced storage
  useEffect(() => {
    if (isInitialized && userEmail) {
      storageService.saveStudents(userEmail, students);
    }
  }, [students, isInitialized, userEmail]);

  const handleLogin = (role: UserRole, email: string, studentId?: string) => {
    setUserEmail(email);
    setUserRole(role);
    setIsLoggedIn(true);
    localStorage.setItem('isLoggedIn', 'true');
    localStorage.setItem('userRole', role);
    localStorage.setItem('userEmail', email);

    if (studentId) {
      setCurrentStudentId(studentId);
      localStorage.setItem('currentStudentId', studentId);
    }

    // Immediately load data for this specific email
    const loadedData = storageService.getStudents(email);
    setStudents(loadedData);
    setIsInitialized(true);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUserRole(null);
    setCurrentStudentId(null);
    setUserEmail('');
    localStorage.removeItem('isLoggedIn');
    localStorage.removeItem('userRole');
    localStorage.removeItem('currentStudentId');
    localStorage.removeItem('userEmail');
    setStudents([]);
    setIsInitialized(false);
  };

  const handleAddStudent = (name: string) => {
    const newStudent: StudentRecord = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      avatar: getAvatarUrl(name),
      history: [],
      isFlagged: false,
      feedback: [],
      conversations: []
    };
    setStudents(prev => [...prev, newStudent]);
  };

  const handleUpdateStudent = (id: string, updates: Partial<StudentRecord>) => {
    setStudents(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
  };

  const handleDeleteStudent = (id: string) => {
    setStudents(prev => prev.filter(s => s.id !== id));
  };

  const handleAnalysisResult = (studentId: string, analysis: EmotionalAnalysis) => {
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) {
        const history = [...s.history, analysis];
        return {
          ...s,
          lastAnalysis: analysis,
          history,
          isFlagged: analysis.stressScore >= 7
        };
      }
      return s;
    }));
  };

  const handleSendFeedback = (id: string, text: string) => {
    const feedback = {
      id: Math.random().toString(36).substr(2, 9),
      text,
      date: new Date().toLocaleString()
    };
    setStudents(prev => prev.map(s => s.id === id ? { ...s, feedback: [feedback, ...(s.feedback || [])] } : s));
  };

  const handleSendChatRequest = (targetId: string) => {
    if (!currentStudentId) return;
    setStudents(prev => prev.map(s => {
      if (s.id === targetId || s.id === currentStudentId) {
        const otherId = s.id === targetId ? currentStudentId : targetId;
        const conversations = s.conversations || [];
        if (!conversations.find(c => c.participantId === otherId)) {
          return {
            ...s,
            conversations: [...conversations, { 
              participantId: otherId, 
              initiatorId: currentStudentId, 
              status: 'pending', 
              messages: [] 
            } as Conversation]
          };
        }
      }
      return s;
    }));
  };

  const handleRespondChatRequest = (targetId: string, accept: boolean) => {
    if (!currentStudentId) return;
    const status = accept ? 'accepted' : 'rejected';
    setStudents(prev => prev.map(s => {
      if (s.id === targetId || s.id === currentStudentId) {
        const otherId = s.id === targetId ? currentStudentId : targetId;
        return {
          ...s,
          conversations: (s.conversations || []).map(c => 
            c.participantId === otherId ? { ...c, status } : c
          )
        };
      }
      return s;
    }));
  };

  const handleSendMessage = (targetId: string, text: string) => {
    if (!currentStudentId) return;
    const newMessage: ChatMessage = {
      id: Math.random().toString(36).substr(2, 9),
      senderId: currentStudentId,
      text,
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    setStudents(prev => prev.map(s => {
      if (s.id === targetId || s.id === currentStudentId) {
        const otherId = s.id === targetId ? currentStudentId : targetId;
        return {
          ...s,
          conversations: (s.conversations || []).map(c => 
            c.participantId === otherId ? { ...c, messages: [...c.messages, newMessage] } : c
          )
        };
      }
      return s;
    }));
  };

  if (!isLoggedIn) {
    return <Login onLogin={handleLogin} students={students} />;
  }

  const currentStudent = students.find(s => s.id === currentStudentId);
  const studentViewStudents = currentStudent ? [currentStudent] : [];

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={handleLogout} 
        userRole={userRole!} 
      />

      <main className="flex-1 overflow-y-auto p-8">
        <div className="max-w-7xl mx-auto">
          {activeTab === 'dashboard' && (
            <Dashboard 
              students={userRole === UserRole.STUDENT ? studentViewStudents : students} 
              isStudentView={userRole === UserRole.STUDENT}
              onSendFeedback={handleSendFeedback}
              setActiveTab={setActiveTab}
            />
          )}
          {activeTab === 'capture' && (
            <CaptureUI 
              students={studentViewStudents} 
              onResult={handleAnalysisResult} 
              isStudentView={true} 
            />
          )}
          {activeTab === 'journals' && (
            <JournalUI 
              students={userRole === UserRole.STUDENT ? studentViewStudents : students} 
              isStudentView={userRole === UserRole.STUDENT} 
            />
          )}
          {activeTab === 'roster' && userRole === UserRole.TEACHER && (
            <StudentRoster 
              students={students} 
              onAddStudent={handleAddStudent} 
              onUpdateStudent={handleUpdateStudent}
              onDeleteStudent={handleDeleteStudent}
              onSendFeedback={handleSendFeedback}
            />
          )}
          {activeTab === 'status' && userRole === UserRole.TEACHER && (
            <StatusMonitor 
              students={students} 
              onSendFeedback={handleSendFeedback} 
            />
          )}
          {activeTab === 'chat' && userRole === UserRole.STUDENT && currentStudent && (
            <StudentChat 
              currentStudent={currentStudent}
              allStudents={students}
              onSendRequest={handleSendChatRequest}
              onRespondRequest={handleRespondChatRequest}
              onSendMessage={handleSendMessage}
            />
          )}
          {activeTab === 'settings' && (
            <Settings 
              theme={theme} 
              setTheme={setTheme} 
              userRole={userRole!}
              student={currentStudent}
              onUpdateStudent={handleUpdateStudent}
              allStudents={students}
              userEmail={userEmail}
              onResetDatabase={() => {
                if(window.confirm(`Clear all data for ${userEmail}?`)) {
                  storageService.clearAllForUser(userEmail);
                  setStudents([]);
                }
              }}
              onImportDatabase={(imported) => setStudents(imported)}
            />
          )}
        </div>
      </main>
    </div>
  );
};

