import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import CaptureUI from './components/CaptureUI';
import JournalUI from './components/JournalUI';
import StudentRoster from './components/StudentRoster';
import Settings from './components/Settings';
import Login from './components/Login';
import StatusMonitor from './components/StatusMonitor';
import StudentChat from './components/StudentChat';
import ProfileSetup from './components/ProfileSetup';
import InvitationFinder from './components/InvitationFinder';
import { storageService } from './services/storageService';
import { StudentRecord, EmotionalAnalysis, UserRole } from './types';

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(() => localStorage.getItem('isLoggedIn') === 'true');
  const [userRole, setUserRole] = useState<UserRole | null>(() => (localStorage.getItem('userRole') as UserRole) || null);
  const [userEmail, setUserEmail] = useState<string>(() => localStorage.getItem('userEmail') || '');
  const [currentStudentId, setCurrentStudentId] = useState<string | null>(() => localStorage.getItem('currentStudentId') || null);
  const [teacherNamespace, setTeacherNamespace] = useState<string>(() => localStorage.getItem('teacherNamespace') || '');

  const [activeTab, setActiveTab] = useState<'dashboard' | 'capture' | 'roster' | 'journals' | 'settings' | 'status' | 'chat'>('dashboard');
  const [students, setStudents] = useState<StudentRecord[]>([]);
  const [isInitialized, setIsInitialized] = useState(false);
  const [theme, setTheme] = useState<'light' | 'dark'>(() => (localStorage.getItem('theme') as 'light' | 'dark') || 'light');

  useEffect(() => {
    if (teacherNamespace) {
      const savedData = storageService.getStudents(teacherNamespace);
      setStudents(savedData);
      setIsInitialized(true);
    }
  }, [teacherNamespace]);

  useEffect(() => {
    if (theme === 'dark') document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    if (isInitialized && teacherNamespace && userRole === UserRole.TEACHER) {
      storageService.saveStudents(teacherNamespace, students);
    }
  }, [students, isInitialized, userRole, teacherNamespace]);

  const handleLogin = (role: UserRole, email: string) => {
    setUserEmail(email);
    setUserRole(role);
    setIsLoggedIn(true);
    localStorage.setItem('isLoggedIn', 'true');
    localStorage.setItem('userRole', role);
    localStorage.setItem('userEmail', email);

    if (role === UserRole.TEACHER) {
      setTeacherNamespace(email);
      localStorage.setItem('teacherNamespace', email);
    } else {
      // For student, try to find an invitation in the last used namespace or wait for Finder
      const lastNs = localStorage.getItem('teacherNamespace');
      if (lastNs) {
        const data = storageService.getStudents(lastNs);
        const found = data.find(s => s.email.toLowerCase() === email.toLowerCase());
        if (found) {
          setTeacherNamespace(lastNs);
          setCurrentStudentId(found.id);
          localStorage.setItem('currentStudentId', found.id);
        }
      }
    }
  };

  const handleClaimInvitation = (teacherEmail: string) => {
    const data = storageService.getStudents(teacherEmail);
    const found = data.find(s => s.email.toLowerCase() === userEmail.toLowerCase());

    if (found) {
      setTeacherNamespace(teacherEmail);
      localStorage.setItem('teacherNamespace', teacherEmail);
      setCurrentStudentId(found.id);
      localStorage.setItem('currentStudentId', found.id);
      setStudents(data);
      setIsInitialized(true);
    } else {
      alert("No pending invitation found for your email in that classroom. Please check the teacher's email address.");
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUserRole(null);
    setCurrentStudentId(null);
    setUserEmail('');
    localStorage.removeItem('isLoggedIn');
    localStorage.removeItem('userRole');
    localStorage.removeItem('currentStudentId');
    localStorage.removeItem('userEmail');
    setStudents([]);
    setIsInitialized(false);
  };

  const handleAddStudent = (email: string) => {
    const newStudent: StudentRecord = {
      id: Math.random().toString(36).substr(2, 9),
      email,
      name: '',
      avatar: '',
      isProfileComplete: false,
      history: [],
      isFlagged: false,
      feedback: [],
      conversations: []
    };
    setStudents(prev => [...prev, newStudent]);
  };

  const handleUpdateStudent = (id: string, updates: Partial<StudentRecord>) => {
    setStudents(prev => {
      const updated = prev.map(s => s.id === id ? { ...s, ...updates } : s);
      // If we're updating the local student profile, we must also update the teacher's storage
      if (userRole === UserRole.STUDENT && teacherNamespace) {
        storageService.saveStudents(teacherNamespace, updated);
      }
      return updated;
    });
  };

  const handleAnalysisResult = (studentId: string, analysis: EmotionalAnalysis) => {
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) {
        const history = [...s.history, analysis];
        return { ...s, lastAnalysis: analysis, history, isFlagged: analysis.stressScore >= 7 };
      }
      return s;
    }));
  };

  const handleSendFeedback = (id: string, text: string) => {
    const feedback = { id: Math.random().toString(36).substr(2, 9), text, date: new Date().toLocaleString() };
    setStudents(prev => prev.map(s => s.id === id ? { ...s, feedback: [feedback, ...(s.feedback || [])] } : s));
  };

  if (!isLoggedIn) {
    return <Login onLogin={handleLogin} />;
  }

  // STUDENT ONBOARDING FLOW
  if (userRole === UserRole.STUDENT) {
    if (!teacherNamespace || !currentStudentId) {
      return <InvitationFinder onClaim={handleClaimInvitation} onLogout={handleLogout} />;
    }
    const currentStudent = students.find(s => s.id === currentStudentId);
    if (currentStudent && !currentStudent.isProfileComplete) {
      return (
        <ProfileSetup 
          student={currentStudent} 
          teacherEmail={teacherNamespace}
          onComplete={(name, avatar) => handleUpdateStudent(currentStudent.id, { name, avatar, isProfileComplete: true })}
          onLogout={handleLogout}
        />
      );
    }
  }

  const currentStudent = students.find(s => s.id === currentStudentId);
  const studentViewStudents = currentStudent ? [currentStudent] : [];

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={handleLogout} 
        userRole={userRole!} 
      />

      <main className="flex-1 overflow-y-auto p-8">
        <div className="max-w-7xl mx-auto">
          {activeTab === 'dashboard' && (
            <Dashboard 
              students={userRole === UserRole.STUDENT ? studentViewStudents : students} 
              isStudentView={userRole === UserRole.STUDENT}
              onSendFeedback={handleSendFeedback}
              setActiveTab={setActiveTab}
            />
          )}
          {activeTab === 'capture' && (
            <CaptureUI 
              students={studentViewStudents} 
              onResult={handleAnalysisResult} 
              isStudentView={true} 
            />
          )}
          {activeTab === 'journals' && (
            <JournalUI 
              students={userRole === UserRole.STUDENT ? studentViewStudents : students} 
              isStudentView={userRole === UserRole.STUDENT} 
            />
          )}
          {activeTab === 'roster' && userRole === UserRole.TEACHER && (
            <StudentRoster 
              students={students} 
              onAddStudent={handleAddStudent} 
              onUpdateStudent={handleUpdateStudent}
              onDeleteStudent={id => setStudents(prev => prev.filter(s => s.id !== id))}
              onSendFeedback={handleSendFeedback}
            />
          )}
          {activeTab === 'status' && userRole === UserRole.TEACHER && (
            <StatusMonitor students={students} onSendFeedback={handleSendFeedback} />
          )}
          {activeTab === 'chat' && userRole === UserRole.STUDENT && currentStudent && (
            <StudentChat currentStudent={currentStudent} allStudents={students} onSendRequest={() => {}} onRespondRequest={() => {}} onSendMessage={() => {}} />
          )}
          {activeTab === 'settings' && (
            <Settings 
              theme={theme} setTheme={setTheme} userRole={userRole!} student={currentStudent} 
              onUpdateStudent={handleUpdateStudent} allStudents={students} userEmail={userEmail}
              onResetDatabase={() => { storageService.clearAllForUser(userEmail); setStudents([]); }}
              onImportDatabase={setStudents}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

