}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [roleSelection, setRoleSelection] = useState<UserRole | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    /* global google */
    if (typeof window !== 'undefined' && (window as any).google) {
      (window as any).google.accounts.id.initialize({
        // This is a placeholder client ID. In a production environment, this would be the developer's real ID.
        client_id: "721721544490-v88o7r53g0skh0h0p9b0l498t3n9v2l0.apps.googleusercontent.com", 
        callback: handleCredentialResponse,
        auto_select: false,
        cancel_on_tap_outside: true,
      });

      if (roleSelection) {
        (window as any).google.accounts.id.renderButton(
          document.getElementById("google-signin-btn"),
          { 
            theme: "outline", 
            size: "large", 
            width: 320, 
            shape: "pill",
            text: roleSelection === UserRole.TEACHER ? "signin_with" : "continue_with",
            logo_alignment: "left"
          }
        );
      }
    }
  }, [roleSelection]);

  const handleCredentialResponse = (response: any) => {
    setIsLoading(true);
    try {
      // Decode JWT payload to get real user details from Google
      const base64Url = response.credential.split('.')[1];
      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
      const jsonPayload = decodeURIComponent(atob(base64).split('').map((c) => {
        return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
      }).join(''));

      const payload = JSON.parse(jsonPayload);

      // Simulate slight network delay for "authenticating" feel
      setTimeout(() => {
        onLogin(roleSelection!, payload.email, payload.name, payload.picture);
        setIsLoading(false);
      }, 1000);
    } catch (error) {
      console.error("Auth Decoding Error:", error);
      setIsLoading(false);
      alert("Google Sign-In failed. Please try again.");
    }
