import React, { useState } from 'react';
import { StudentRecord } from '../types';
import { generateInvitationEmail } from '../services/geminiService';

interface StudentRosterProps {
  students: StudentRecord[];
  teacherEmail: string;
  onAddStudent: (email: string) => void;
  onUpdateStudent: (id: string, updates: Partial<StudentRecord>) => void;
  onDeleteStudent: (id: string) => void;
  onSendFeedback: (id: string, text: string) => void;
}

const StudentRoster: React.FC<StudentRosterProps> = ({ students, teacherEmail, onAddStudent, onDeleteStudent, onSendFeedback }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newStudentEmail, setNewStudentEmail] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [generatedEmail, setGeneratedEmail] = useState<{subject: string, body: string, targetEmail: string} | null>(null);

  const filteredStudents = students.filter(s => 
    s.email.toLowerCase().includes(searchQuery.toLowerCase()) || 
    s.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handlePrepareInvite = async (e: React.FormEvent) => {
    e.preventDefault();
    const email = newStudentEmail.trim();
    if (email.includes('@')) {
      setIsProcessing(true);

      // 1. Use Gemini to write a professional invitation
      const content = await generateInvitationEmail(teacherEmail, email);

      if (content) {
        setGeneratedEmail({ ...content, targetEmail: email });
        // Add to local roster in pending state
        onAddStudent(email);
      }

      setIsProcessing(false);
    }
  };

  const handleSendViaGmail = () => {
    if (!generatedEmail) return;

    // Construct the Real Gmail Deep Link
    const subject = encodeURIComponent(generatedEmail.subject);
    const body = encodeURIComponent(generatedEmail.body);
    const gmailUrl = `https://mail.google.com/mail/?view=cm&fs=1&to=${generatedEmail.targetEmail}&su=${subject}&body=${body}`;

    // Open Gmail in a new tab for the teacher to hit 'Send'
    window.open(gmailUrl, '_blank');

    // Reset modal state
    setNewStudentEmail('');
    setGeneratedEmail(null);
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Classroom Roster</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium italic">Integrated Gmail invitation dispatch.</p>
        </div>

        <div className="flex items-center gap-4 w-full md:w-auto">
          <input 
            type="text" placeholder="Search students..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)}
            className="px-6 py-3.5 rounded-[1.5rem] border border-slate-200 dark:border-slate-800 outline-none focus:ring-2 focus:ring-indigo-600 bg-white dark:bg-slate-900 dark:text-white transition-all shadow-sm md:w-80 font-medium"
          />
          <button 
            onClick={() => { setIsModalOpen(true); setGeneratedEmail(null); }}
            className="bg-indigo-600 text-white px-8 py-3.5 rounded-[1.5rem] font-black text-sm uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl flex items-center gap-2 active:scale-95"
          >
            <span>Add Student</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredStudents.map((student) => (
          <div key={student.id} className={`bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border-2 transition-all relative ${student.isProfileComplete ? 'border-slate-100 dark:border-slate-800' : 'border-dashed border-slate-300 dark:border-slate-700'}`}>
            <button onClick={() => onDeleteStudent(student.id)} className="absolute top-6 right-6 p-2 rounded-xl text-slate-300 hover:text-rose-500 transition-colors">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
            </button>
            <div className="flex items-center gap-5 mb-8">
              <img src={student.isProfileComplete ? student.avatar : 'https://api.dicebear.com/7.x/initials/svg?seed=PENDING'} className={`w-16 h-16 rounded-3xl object-cover shadow-xl ${!student.isProfileComplete && 'grayscale opacity-50'}`} alt="" />
              <div className="min-w-0">
                <h3 className="font-black text-slate-800 dark:text-white truncate text-lg">{student.isProfileComplete ? student.name : 'Waiting for Sign-in'}</h3>
                <p className="text-xs font-bold text-slate-400 dark:text-slate-500 truncate">{student.email}</p>
              </div>
            </div>
            <div className="space-y-4 mb-4">
              <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest">
                <span className="text-slate-400">Profile Status</span>
                <span className={student.isProfileComplete ? 'text-emerald-500' : 'text-amber-500'}>{student.isProfileComplete ? 'Verified' : 'Invitation Sent'}</span>
              </div>
              <div className="h-2 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full transition-all duration-1000 ${student.isProfileComplete ? 'bg-emerald-500 w-full' : 'bg-amber-500 w-1/3'}`} />
              </div>
            </div>
          </div>
        ))}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setIsModalOpen(false)} />
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-md rounded-[3rem] shadow-2xl p-10 animate-in zoom-in-95 duration-300">
            {generatedEmail ? (
              <div className="space-y-8 animate-in slide-in-from-bottom-4">
