                    <div>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Subject Line</p>
                        <p className="text-xs font-bold dark:text-white leading-relaxed">{generatedEmail.subject}</p>
                    </div>
                    <div className="pt-2 border-t border-slate-100 dark:border-slate-900">
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Message Preview</p>
                        <p className="text-[10px] text-slate-500 italic leading-relaxed line-clamp-4">{generatedEmail.body}</p>
                    </div>
                </div>

                <div className="space-y-3">
                    <button 
                        onClick={handleSendViaGmail} 
                        className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-indigo-100 dark:shadow-none hover:bg-indigo-700 transition-all flex items-center justify-center gap-3"
                    >
                        <svg className="w-5 h-5" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M22 2L11 13M22 2L15 22L11 13M11 13L2 9L22 2" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                        Send with Gmail
                    </button>
                    <button onClick={() => setGeneratedEmail(null)} className="w-full py-4 text-xs font-bold text-slate-400 hover:text-slate-600 transition-colors uppercase tracking-widest">
                        Cancel Invitation
                    </button>
                </div>
              </div>
            ) : (
              <>
                <h3 className="text-2xl font-black text-slate-800 dark:text-white mb-2">Invite Student</h3>
                <p className="text-sm text-slate-500 mb-8 leading-relaxed">Enter the student's Gmail. We'll generate a personalized invitation that you can send from your account.</p>
                <form onSubmit={handlePrepareInvite} className="space-y-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Student Gmail</label>
                    <input 
                      type="email" autoFocus required value={newStudentEmail} onChange={(e) => setNewStudentEmail(e.target.value)} placeholder="student@school.edu"
                      className="w-full p-4 rounded-2xl border-2 border-slate-50 dark:border-slate-800 bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-white outline-none focus:border-indigo-600 transition-all font-bold"
                    />
                  </div>
                  <button type="submit" disabled={isProcessing} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-indigo-700 shadow-xl transition-all disabled:opacity-50 flex items-center justify-center gap-3">
                    {isProcessing ? <><div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin" /> Drafting...</> : 'Prepare Invite'}
                  </button>
                </form>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

