  useEffect(() => {
    const checkGsi = () => {
      if ((window as any).google?.accounts?.id) {
        setIsGsiLoaded(true);
        return true;
      }
      return false;
    };

    if (!checkGsi()) {
      const interval = setInterval(() => {
        if (checkGsi()) clearInterval(interval);
      }, 100);
      return () => clearInterval(interval);
    }
  }, []);

  // 2. Render the official button once the library AND selection are ready
  useEffect(() => {
    if (isGsiLoaded && roleSelection) {
