        {isLoading && (
          <div className="absolute top-0 left-0 w-full h-1 bg-slate-100 dark:bg-slate-800 overflow-hidden">
            <div className="h-full bg-indigo-600 animate-[progress_2s_infinite]" style={{width: '30%'}} />
          </div>
        )}

