interface LoginProps {
  onLogin: (role: UserRole, email: string, name?: string, picture?: string) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [roleSelection, setRoleSelection] = useState<UserRole | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [gsiStatus, setGsiStatus] = useState<'loading' | 'ready' | 'error'>('loading');

  const handleCredentialResponse = useCallback((response: any) => {
    setIsLoading(true);
    try {
      const base64Url = response.credential.split('.')[1];
      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
      const jsonPayload = decodeURIComponent(atob(base64).split('').map((c) => {
        return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
      }).join(''));

      const payload = JSON.parse(jsonPayload);

      setTimeout(() => {
        onLogin(roleSelection!, payload.email, payload.name, payload.picture);
        setIsLoading(false);
      }, 800);
    } catch (error) {
      console.error("Auth Decoding Error:", error);
      setIsLoading(false);
      alert("Verification failed. Please refresh and try again.");
    }
  }, [roleSelection, onLogin]);

  useEffect(() => {
    const initGsi = () => {
      if ((window as any).google?.accounts?.id) {
        (window as any).google.accounts.id.initialize({
          client_id: "721721544490-v88o7r53g0skh0h0p9b0l498t3n9v2l0.apps.googleusercontent.com",
          callback: handleCredentialResponse,
          auto_select: false,
        });
        setGsiStatus('ready');
      } else {
        setGsiStatus('error');
      }
    };

    // If script already loaded
    if ((window as any).google?.accounts?.id) {
      initGsi();
    } else {
      // Wait for script to load via DOM events
      const script = document.querySelector('script[src*="gsi/client"]');
      if (script) {
        script.addEventListener('load', initGsi);
        return () => script.removeEventListener('load', initGsi);
